-- Enable RLS
-- Run this in your Supabase SQL Editor

-- 1. Madrasahs Table (Extends Auth User)
CREATE TABLE IF NOT EXISTS public.madrasahs (
    id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    phone TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. Classes Table
CREATE TABLE IF NOT EXISTS public.classes (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    class_name TEXT NOT NULL,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 3. Students Table
CREATE TABLE IF NOT EXISTS public.students (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
    -- Prevent exact duplicates for same madrasah/class/student/phone
    CONSTRAINT unique_student_per_madrasah UNIQUE (madrasah_id, class_id, student_name, guardian_phone)
);

-- 4. Recent Calls Table
CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT, -- Denormalized for display speed
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    called_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- ENABLE ROW LEVEL SECURITY
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- POLICIES
-- Madrasahs
CREATE POLICY "Madrasahs can view their own profile" ON public.madrasahs FOR SELECT USING (auth.uid() = id);
CREATE POLICY "Madrasahs can update their own profile" ON public.madrasahs FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "System can insert madrasah profile" ON public.madrasahs FOR INSERT WITH CHECK (auth.uid() = id);

-- Classes
CREATE POLICY "Madrasahs can manage their own classes" ON public.classes 
    FOR ALL USING (auth.uid() = madrasah_id) WITH CHECK (auth.uid() = madrasah_id);

-- Students
CREATE POLICY "Madrasahs can manage their own students" ON public.students 
    FOR ALL USING (auth.uid() = madrasah_id) WITH CHECK (auth.uid() = madrasah_id);

-- Recent Calls
CREATE POLICY "Madrasahs can manage their own call logs" ON public.recent_calls 
    FOR ALL USING (auth.uid() = madrasah_id) WITH CHECK (auth.uid() = madrasah_id);

-- FUNCTION: Auto-create madrasah profile on signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger AS $$
BEGIN
  INSERT INTO public.madrasahs (id, name)
  VALUES (new.id, 'নতুন মাদরাসা');
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE OR REPLACE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

export interface Madrasah {
