}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { Phone, Plus, X, User, Edit2, ArrowLeft, Loader2, Info } from 'lucide-react';
import { Student } from '../types';

const Students: React.FC = () => {
  const { classId } = useParams();
  const navigate = useNavigate();
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showDetails, setShowDetails] = useState<Student | null>(null);
  const [className, setClassName] = useState('');

  const [editId, setEditId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', phone: '' });

  useEffect(() => {
    fetchClassAndStudents();
  }, [classId]);

  const fetchClassAndStudents = async () => {
    if (!classId) return;

    const [classRes, studentRes] = await Promise.all([
      supabase.from('classes').select('class_name').eq('id', classId).single(),
      supabase.from('students').select('*').eq('class_id', classId).order('student_name')
    ]);

    if (classRes.data) setClassName(classRes.data.class_name);
    if (studentRes.data) setStudents(studentRes.data);
    setLoading(false);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone) return;

    const { data: userData } = await supabase.auth.getUser();
    if (!userData.user || !classId) return;

    const payload = {
      student_name: formData.name,
      guardian_phone: formData.phone,
      class_id: classId,
      madrasah_id: userData.user.id
    };

    if (editId) {
      await supabase.from('students').update(payload).eq('id', editId);
    } else {
      await supabase.from('students').insert(payload);
    }

    setShowModal(false);
    setEditId(null);
    setFormData({ name: '', phone: '' });
    fetchClassAndStudents();
  };

  const startEdit = (student: Student) => {
    setEditId(student.id);
    setFormData({ name: student.student_name, phone: student.guardian_phone });
    setShowDetails(null);
    setShowModal(true);
  };

  const makeCall = async (student: Student) => {
    await supabase.from('recent_calls').insert({
      student_id: student.id,
      student_name: student.student_name,
      guardian_phone: student.guardian_phone,
      madrasah_id: student.madrasah_id
    });
    window.location.href = `tel:${student.guardian_phone}`;
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-green-600" /></div>;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/classes')} className="text-gray-500 hover:bg-gray-100 p-2 rounded-full transition-colors"><ArrowLeft /></button>
        <h2 className="text-2xl font-bold">{className}</h2>
      </div>

      <div className="space-y-3">
        {students.length > 0 ? (
          students.map((student) => (
            <div 
              key={student.id} 
              onClick={() => setShowDetails(student)}
              className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between active:bg-gray-50 transition-colors cursor-pointer"
            >
              <div className="flex items-center gap-3">
                <div className="bg-gray-50 p-2 rounded-full"><User size={20} className="text-gray-400" /></div>
                <div>
                  <h3 className="font-bold text-gray-800">{student.student_name}</h3>
                  <p className="text-xs text-gray-500">{student.guardian_phone}</p>
                </div>
              </div>
              <div className="flex gap-1">
                <button 
                  onClick={(e) => { e.stopPropagation(); makeCall(student); }} 
                  className="bg-green-100 text-green-700 p-3 rounded-full hover:bg-green-200"
                >
                  <Phone size={18} fill="currentColor" />
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-gray-300">
            <p className="text-gray-500">এই ক্লাসে কোনো ছাত্র নেই।</p>
          </div>
        )}
      </div>

      {/* Floating Action Button */}
      <button 
        onClick={() => { setEditId(null); setFormData({name:'', phone:''}); setShowModal(true); }}
        className="fixed bottom-24 right-6 bg-green-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center active:scale-90 transition-transform z-40"
      >
        <Plus size={28} />
      </button>

      {/* Student Details Modal (Step 3) */}
      {showDetails && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] sm:rounded-3xl p-8 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-start mb-6">
              <div className="bg-green-100 p-4 rounded-3xl text-green-700 mb-4">
                <User size={40} />
              </div>
              <button onClick={() => setShowDetails(null)} className="p-2 bg-gray-100 rounded-full"><X size={20}/></button>
            </div>

            <div className="space-y-6">
              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">ছাত্রের নাম</h4>
                <p className="text-2xl font-bold text-gray-800">{showDetails.student_name}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">শ্রেণি</h4>
                <p className="text-lg font-medium text-gray-700">{className}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">অভিভাবকের ফোন</h4>
                <p className="text-xl font-mono font-bold text-green-700">{showDetails.guardian_phone}</p>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-4">
                <button 
                  onClick={() => makeCall(showDetails)}
                  className="flex items-center justify-center gap-2 bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-200 active:scale-95 transition-transform"
                >
                  <Phone size={20} fill="currentColor" />
                  কল করুন
                </button>
                <button 
                  onClick={() => startEdit(showDetails)}
                  className="flex items-center justify-center gap-2 bg-gray-100 text-gray-700 py-4 rounded-2xl font-bold active:scale-95 transition-transform"
                >
                  <Edit2 size={20} />
                  এডিট
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add/Edit Modal (Step 4) */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-[80] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-t-2xl sm:rounded-3xl p-6 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold">{editId ? 'তথ্য সংশোধন' : 'নতুন ছাত্র যোগ করুন'}</h3>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-full"><X /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-5">
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">ছাত্রের নাম (বাংলায়)</label>
                <input 
                  required
                  type="text" 
                  placeholder="উদাঃ আব্দুল্লাহ"
                  className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">অভিভাবকের মোবাইল নম্বর</label>
                <input 
                  required
                  type="tel" 
                  placeholder="01XXXXXXXXX"
                  className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                  value={formData.phone}
                  onChange={e => setFormData({...formData, phone: e.target.value})}
                />
              </div>
              <button type="submit" className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-100 active:scale-95 transition-all">
                {editId ? 'আপডেট করুন' : 'সংরক্ষণ করুন'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Students;

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Settings, User, Building, Mail, Save, Phone } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah }) => {
  const [name, setName] = useState(madrasah?.name || '');
  const [phone, setPhone] = useState(madrasah?.phone || '');
  const [saving, setSaving] = useState(false);
  const [email, setEmail] = useState('');

  React.useEffect(() => {
    const getUser = async () => {
      const { data } = await supabase.auth.getUser();
      if (data.user) setEmail(data.user.email || '');
    };
    getUser();
  }, []);

  const handleUpdate = async () => {
    if (!name.trim()) return;
    setSaving(true);
    const { error } = await supabase
      .from('madrasahs')
      .update({ name, phone })
      .eq('id', madrasah?.id);

    if (!error) {
      alert('সফলভাবে আপডেট করা হয়েছে!');
      window.location.reload(); 
    } else {
      alert('ত্রুটি: ' + error.message);
    }
    setSaving(false);
  };

  const handleLogout = async () => {
    if (window.confirm('আপনি কি নিশ্চিত যে আপনি লগআউট করতে চান?')) {
      await supabase.auth.signOut();
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold">অ্যাকাউন্ট প্রোফাইল</h2>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 space-y-6">
        <div className="flex flex-col items-center">
          <div className="w-24 h-24 bg-green-600 text-white rounded-full flex items-center justify-center mb-4 shadow-lg shadow-green-100">
            <Building size={48} />
          </div>
          <h3 className="text-2xl font-bold text-gray-800">{madrasah?.name}</h3>
          <p className="text-gray-500 font-medium">{email}</p>
        </div>

        <div className="space-y-5 pt-6 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-600 mb-2 flex items-center gap-2">
              <Building size={16} className="text-green-600" /> মাদরাসার নাম
            </label>
            <input 
              type="text" 
              className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all"
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="মাদরাসার নাম লিখুন"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-600 mb-2 flex items-center gap-2">
              <Phone size={16} className="text-green-600" /> মাদরাসার ফোন নম্বর
            </label>
            <input 
              type="tel" 
              className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              placeholder="01XXXXXXXXX"
            />
          </div>

          <button 
            onClick={handleUpdate}
            disabled={saving}
            className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-green-700 active:scale-95 transition-all shadow-lg shadow-green-100"
          >
            <Save size={20} />
            {saving ? 'প্রসেসিং হচ্ছে...' : 'তথ্য সংরক্ষণ করুন'}
          </button>
        </div>
      </div>

      <div className="space-y-3">
        <button 
          onClick={handleLogout}
          className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-100 active:scale-95 transition-all"
        >
          <LogOut size={20} />
          লগআউট করুন
        </button>
      </div>

      <div className="pt-4 text-center">
        <p className="text-xs text-gray-400 font-medium">Madrasah Contact App v1.2.0 • Build for Android</p>
      </div>
    </div>
  );
};

export default Account;

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Upload, FileText, AlertCircle, CheckCircle2, Loader2, Info } from 'lucide-react';

const ImportData: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [report, setReport] = useState<{success: number, error: string} | null>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith('.csv')) {
      alert('অনুগ্রহ করে শুধুমাত্র CSV ফাইল আপলোড করুন।');
      return;
    }

    setLoading(true);
    setReport(null);

    const reader = new FileReader();
    reader.onload = async (event) => {
      try {
        const text = event.target?.result as string;
        const rows = text.split('\n').map(r => r.trim()).filter(Boolean);

        if (rows.length < 1) throw new Error("ফাইলটি খালি!");

        // Skip header if common keywords found
        const firstRow = rows[0].toLowerCase();
        const startIdx = (firstRow.includes('name') || firstRow.includes('phone') || firstRow.includes('নাম')) ? 1 : 0;

        const { data: userData } = await supabase.auth.getUser();
        const madrasahId = userData.user?.id;
        if (!madrasahId) throw new Error("লগইন সেশন পাওয়া যায়নি।");

        let successCount = 0;
        const errors: string[] = [];

        // Step 1: Extract and Unique Classes
        const rawEntries = rows.slice(startIdx).map(row => {
          const parts = row.split(',').map(s => s.trim());
          return { name: parts[0], className: parts[1], phone: parts[2] };
        }).filter(e => e.name && e.className && e.phone);

        const uniqueClassNames = Array.from(new Set(rawEntries.map(r => r.className)));
        const classMap: Record<string, string> = {};

        // Ensure classes exist
        for (const cName of uniqueClassNames) {
          const { data: existing } = await supabase.from('classes')
            .select('id')
            .eq('class_name', cName)
            .eq('madrasah_id', madrasahId)
            .single();

          if (!existing) {
            const { data: created, error: createError } = await supabase.from('classes')
              .insert({ class_name: cName, madrasah_id: madrasahId })
              .select('id')
              .single();
            if (created) classMap[cName] = created.id;
            if (createError) errors.push(`শ্রেণি তৈরিতে সমস্যা: ${cName}`);
          } else {
            classMap[cName] = existing.id;
          }
        }

        // Step 2: Batch Student Prep
        const studentData = rawEntries.map(entry => ({
          student_name: entry.name,
          class_id: classMap[entry.className],
          guardian_phone: entry.phone,
          madrasah_id: madrasahId
        })).filter(s => s.class_id);

        if (studentData.length > 0) {
          // Use UPSERT logic via unique constraint if available in SQL, 
          // or just standard insert if we rely on the DB constraint to catch duplicates.
          // Note: Mock client might not support complex upsert, but real Supabase does.
          const { error: insertError } = await supabase.from('students').insert(studentData);

          if (!insertError) {
            successCount = studentData.length;
          } else {
            if (insertError.code === '23505') { // Postgres Unique Violation
               errors.push("কিছু ছাত্র আগে থেকেই ডাটাবেজে আছে, তাই সেগুলো বাদ দেয়া হয়েছে।");
               // In a real scenario, we might want to tell them which ones, 
               // but for bulk import, a general message is often enough for a simple tool.
            } else {
              errors.push(insertError.message);
            }
          }
        }

        setReport({
          success: successCount,
          error: errors.join('. ')
        });
      } catch (err: any) {
        setReport({ success: 0, error: err.message });
      } finally {
        setLoading(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold">একসাথে অনেক তথ্য যুক্ত করুন</h2>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
        <div className="flex items-start gap-3 text-green-700 mb-6 bg-green-50 p-4 rounded-2xl border border-green-100">
          <Info size={24} className="flex-shrink-0 mt-0.5" />
          <div className="text-sm">
            <p className="font-bold mb-1">সঠিক ফাইল ফরম্যাট:</p>
            <p>আপনার CSV ফাইলটি অবশ্যই ৩টি কলামের হতে হবে।</p>
          </div>
        </div>

        <div className="bg-gray-800 p-5 rounded-2xl font-mono text-xs mb-6 text-gray-300 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-2 bg-gray-700 text-[8px] text-gray-500 uppercase tracking-widest">Example CSV</div>
          student_name, class_name, guardian_phone<br/>
          করিম হোসেন, ৫ম শ্রেণি, 01712345678<br/>
          রহিম আলী, ৬ষ্ঠ শ্রেণি, 01812345678
        </div>

        <label className={`w-full border-2 border-dashed border-gray-200 rounded-[2rem] p-12 flex flex-col items-center justify-center cursor-pointer hover:border-green-500 hover:bg-green-50 transition-all ${loading ? 'opacity-50 pointer-events-none' : ''}`}>
          {loading ? (
            <Loader2 className="animate-spin text-green-600 mb-4" size={48} />
          ) : (
            <Upload className="text-green-600 mb-4 bg-green-100 p-4 rounded-full" size={64} />
          )}
          <span className="font-bold text-gray-800 text-lg">{loading ? 'প্রসেসিং হচ্ছে...' : 'CSV ফাইলটি এখানে দিন'}</span>
