// Robust Mock Client Implementation with Chaining Support
class MockSupabase {
  auth = {
    getSession: async () => {
      const session = localStorage.getItem('mock_session');
      return { data: { session: session ? JSON.parse(session) : null }, error: null };
    },
    onAuthStateChange: (callback: any) => {
      // In a real app, this would return a subscription. 
      // For the mock, we just provide the structure.
      return { data: { subscription: { unsubscribe: () => {} } } };
    },
    signInWithPassword: async ({ email }: any) => {
      // Always sign in as the demo user for the mock
      const session = { 
        user: { id: 'demo-user-id', email: email || 'demo@madrasah.com' }, 
        access_token: 'mock-token',
        expires_at: 9999999999 
      };
      localStorage.setItem('mock_session', JSON.stringify(session));
      initMockDB(); // Ensure DB is there on login
      setTimeout(() => window.location.reload(), 100);
      return { data: { session }, error: null };
    },
    signUp: async ({ email }: any) => {
      return { data: { user: { id: 'demo-user-id', email } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem('mock_session');
      setTimeout(() => window.location.reload(), 100);
      return { error: null };
    },
    getUser: async () => {
      const session = localStorage.getItem('mock_session');
      return { data: { user: session ? JSON.parse(session).user : null } };
    }
  };

  from(table: string) {
    const getDB = () => JSON.parse(localStorage.getItem('mock_db') || '{}');
    const saveDB = (db: any) => localStorage.setItem('mock_db', JSON.stringify(db));

    const createChain = (currentData: any[]) => {
      const chain: any = {
        select: (columns?: string) => chain, // Simple mock doesn't handle column selection
        eq: (col: string, val: any) => createChain(currentData.filter(i => i[col] === val)),
        ilike: (col: string, val: string) => {
          const search = val.replace(/%/g, '').toLowerCase();
          return createChain(currentData.filter(i => i[col]?.toLowerCase().includes(search)));
        },
        order: (col: string, { ascending = true } = {}) => createChain([...currentData].sort((a, b) => 
          ascending ? (a[col] > b[col] ? 1 : -1) : (a[col] < b[col] ? 1 : -1)
        )),
        limit: (n: number) => createChain(currentData.slice(0, n)),
        single: async () => ({ data: currentData[0] || null, error: null }),
        insert: async (input: any) => {
          const db = getDB();
          const newData = Array.isArray(input) ? input : [input];
          const rows = newData.map(r => ({ 
            id: Math.random().toString(36).substr(2, 9), 
            ...r, 
            created_at: new Date().toISOString() 
          }));
          db[table] = [...(db[table] || []), ...rows];
          saveDB(db);
          return { data: rows[0], error: null };
        },
        update: async (input: any) => ({
          eq: (col: string, val: any) => {
            const db = getDB();
            db[table] = (db[table] || []).map((i: any) => i[col] === val ? { ...i, ...input } : i);
            saveDB(db);
            return { error: null };
          }
        }),
        delete: async () => ({
          eq: (col: string, val: any) => {
            const db = getDB();
            db[table] = (db[table] || []).filter((i: any) => i[col] !== val);
            saveDB(db);
            return { error: null };
          }
        }),
        // Chain acting as a promise
        then: (onfulfilled: any) => Promise.resolve({ data: currentData, error: null }).then(onfulfilled),
        data: currentData,
        error: null
      };
      return chain;
    };

    return createChain(getDB()[table] || []);
  }
}

