initMockDB();

class MockSupabase {
  auth = {
    getSession: async () => {
      const session = localStorage.getItem('mock_session');
      return { data: { session: session ? JSON.parse(session) : null }, error: null };
    },
    onAuthStateChange: (callback: any) => {
      // Simple mock for auth state change
      return { data: { subscription: { unsubscribe: () => {} } } };
    },
    signInWithPassword: async ({ email }: any) => {
      const session = { 
        user: { id: 'demo-user-id', email: email || 'demo@madrasah.com' }, 
        access_token: 'mock-token',
        expires_at: Math.floor(Date.now() / 1000) + 3600 
      };
      localStorage.setItem('mock_session', JSON.stringify(session));
      initMockDB();
      setTimeout(() => window.location.reload(), 50);
      return { data: { session }, error: null };
    },
    signUp: async ({ email }: any) => {
      return { data: { user: { id: 'demo-user-id', email } }, error: null };
    },
    signOut: async () => {
      localStorage.removeItem('mock_session');
      setTimeout(() => window.location.reload(), 50);
      return { error: null };
    },
    getUser: async () => {
      const session = localStorage.getItem('mock_session');
      return { data: { user: session ? JSON.parse(session).user : null } };
    }
  };

  from(table: string) {
    const getDB = () => {
      try {
        const db = localStorage.getItem('mock_db');
        return db ? JSON.parse(db) : DEMO_DATA;
      } catch {
        return DEMO_DATA;
      }
    };
    const saveDB = (db: any) => localStorage.setItem('mock_db', JSON.stringify(db));

    const createChain = () => {
      const state = {
        filters: [] as { col: string, val: any, type: string }[],
        updateData: null as any,
        insertData: null as any,
        isDelete: false,
        single: false,
        limit: null as number | null,
        order: null as { col: string, asc: boolean } | null,
      };

      const chain: any = {
        select: (columns?: string) => chain,
        eq: (col: string, val: any) => {
          state.filters.push({ col, val, type: 'eq' });
          return chain;
        },
        ilike: (col: string, val: string) => {
          state.filters.push({ col, val: val.replace(/%/g, '').toLowerCase(), type: 'ilike' });
          return chain;
        },
        order: (col: string, { ascending = true } = {}) => {
          state.order = { col, asc: ascending };
          return chain;
        },
        limit: (n: number) => {
          state.limit = n;
          return chain;
        },
        single: () => {
          state.single = true;
          return chain;
        },
        insert: (data: any) => {
          state.insertData = data;
          return chain;
        },
        update: (data: any) => {
          state.updateData = data;
          return chain;
        },
        delete: () => {
          state.isDelete = true;
          return chain;
        },
        // Make the chain thenable so it works with await
        then: (onfulfilled: any) => {
          const db = getDB();
          let data: any = [...(db[table] || [])];
          let error = null;

          // Process Filters
          state.filters.forEach(f => {
            if (f.type === 'eq') data = data.filter((i: any) => i[f.col] === f.val);
            if (f.type === 'ilike') data = data.filter((i: any) => i[f.col]?.toLowerCase().includes(f.val));
          });

          // Sort & Limit
          if (state.order) {
            data.sort((a: any, b: any) => {
              const valA = a[state.order!.col];
              const valB = b[state.order!.col];
              if (state.order!.asc) return valA > valB ? 1 : -1;
              return valA < valB ? 1 : -1;
            });
          }
          if (state.limit !== null) {
            data = data.slice(0, state.limit);
          }

          // Mutations
          if (state.insertData) {
            const newData = Array.isArray(state.insertData) ? state.insertData : [state.insertData];
            const rows = newData.map(r => ({ 
              id: Math.random().toString(36).substr(2, 9), 
              ...r, 
              created_at: new Date().toISOString() 
            }));
            db[table] = [...(db[table] || []), ...rows];
            saveDB(db);
            data = Array.isArray(state.insertData) ? rows : rows[0];
          } else if (state.updateData) {
            // Re-fetch all to apply updates correctly in memory
            const fullTable = [...(db[table] || [])];
            db[table] = fullTable.map((item: any) => {
              let match = true;
              state.filters.forEach(f => {
                if (f.type === 'eq' && item[f.col] !== f.val) match = false;
                if (f.type === 'ilike' && !item[f.col]?.toLowerCase().includes(f.val)) match = false;
              });
              return match ? { ...item, ...state.updateData } : item;
            });
            saveDB(db);
            data = null; 
          } else if (state.isDelete) {
            const fullTable = [...(db[table] || [])];
            db[table] = fullTable.filter((item: any) => {
              let match = true;
              state.filters.forEach(f => {
                if (f.type === 'eq' && item[f.col] !== f.val) match = false;
                if (f.type === 'ilike' && !item[f.col]?.toLowerCase().includes(f.val)) match = false;
              });
              return !match;
            });
            saveDB(db);
            data = null;
          } else if (state.single) {
            data = data[0] || null;
          }

          return Promise.resolve({ data, error }).then(onfulfilled);
        }
      };
      return chain;
    };

    return createChain();
  }
}

export const supabase = isDemoMode ? (new MockSupabase() as any) : createClient(supabaseUrl, supabaseKey);

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase, isDemoMode } from './lib/supabase';
import Layout from './components/Layout';
import Home from './pages/Home';
import Classes from './pages/Classes';
import Students from './pages/Students';
import Account from './pages/Account';
import Login from './pages/Login';
import { AuthState } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    loading: true,
    madrasah: null,
  });
  const [initError, setInitError] = useState<string | null>(null);

  useEffect(() => {
    // Initial Session Check with error handling
    const checkUser = async () => {
      try {
        const { data: { session }, error } = await supabase.auth.getSession();

        if (error) throw error;

        if (session?.user) {
          const { data: madrasah, error: madrasahError } = await supabase
            .from('madrasahs')
            .select('*')
            .eq('id', session.user.id)
            .single();

          if (madrasahError && madrasahError.code !== 'PGRST116') {
             console.error("Madrasah profile fetch error:", madrasahError);
          }

          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err: any) {
        console.error("Initialization error:", err);
        // Only trigger init error if we are NOT in demo mode and there is a real failure
        const isNetworkError = err.message?.toLowerCase().includes('fetch');
        // Check window for isDemoMode logic locally
        if (isNetworkError) {
          setInitError("ডাটাবেসের সাথে সংযোগ করা সম্ভব হচ্ছে না। অনুগ্রহ করে আপনার সেটিংস চেক করুন।");
        }
        setAuth(prev => ({ ...prev, loading: false }));
      }
    };

    checkUser();

    // Listen for auth changes safely
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      try {
        if (session?.user) {
          const { data: madrasah } = await supabase
            .from('madrasahs')
            .select('*')
            .eq('id', session.user.id)
            .single();
          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err) {
        console.error("Auth state change error:", err);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (auth.loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-green-50">
        <div className="flex flex-col items-center p-6 text-center">
          <div className="h-12 w-12 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="mt-4 text-green-700 font-medium">অপেক্ষা করুন...</p>
        </div>
      </div>
    );
  }

  // Only show error screen if we're not logged in AND there's a real init error
  if (initError && !auth.user) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-red-50 p-6">
        <div className="bg-white p-8 rounded-3xl shadow-xl max-w-sm w-full text-center">
          <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
          </div>
          <h2 className="text-xl font-bold text-gray-800 mb-2">সংযোগ ত্রুটি</h2>
          <p className="text-gray-600 mb-6">{initError}</p>
          <button 
            onClick={() => window.location.reload()}
            className="w-full bg-green-600 text-white py-3 rounded-xl font-bold hover:bg-green-700 transition-colors"
          >
            আবার চেষ্টা করুন
          </button>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {auth.user ? (
          <Route element={<Layout madrasahName={auth.madrasah?.name || 'মাদরাসা'} />}>
            <Route path="/" element={<Home />} />
            <Route path="/classes" element={<Classes />} />
            <Route path="/classes/:classId" element={<Students />} />
            <Route path="/account" element={<Account madrasah={auth.madrasah} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        ) : (
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

export default App;

