import React, { useState, useEffect } from 'react';
import { supabase, isDemoMode } from '../lib/supabase';
import { Search, Phone, Clock, User, PlusCircle } from 'lucide-react';
import { Student, RecentCall } from '../types';
import { Link } from 'react-router-dom';

const Home: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState<Student[]>([]);
  const [recentCalls, setRecentCalls] = useState<RecentCall[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchRecentCalls();
  }, []);

  const fetchRecentCalls = async () => {
    const { data } = await supabase
      .from('recent_calls')
      .select('*')
      .order('called_at', { ascending: false })
      .limit(10);
    if (data) setRecentCalls(data);
  };

  const handleSearch = async (val: string) => {
    setSearchTerm(val);
    if (val.length < 2) {
      setSearchResults([]);
      return;
    }

    setLoading(true);

    const { data } = await supabase
      .from('students')
      .select(`*`)
      .ilike('student_name', `%${val}%`)
      .limit(20);

    if (data) {
      if (isDemoMode) {
        const dbStr = localStorage.getItem('mock_db');
        const db = JSON.parse(dbStr || '{}');
        const formatted = data.map((s: any) => ({
          ...s,
          class_name: db.classes?.find((c: any) => c.id === s.class_id)?.class_name || 'সাধারণ শ্রেণি'
        }));
        setSearchResults(formatted);
      } else {
        setSearchResults(data);
      }
    }
    setLoading(false);
  };

  const makeCall = async (student: Partial<Student>) => {
    if (!student.guardian_phone) return;

    const { data: { user } } = await supabase.auth.getUser();

    await supabase.from('recent_calls').insert({
      student_id: student.id || null,
      student_name: student.student_name,
      guardian_phone: student.guardian_phone,
      madrasah_id: user?.id || 'demo-id',
      called_at: new Date().toISOString()
    });

    window.location.href = `tel:${student.guardian_phone}`;
    setTimeout(fetchRecentCalls, 1000);
  };

  return (
    <div className="space-y-6">
      {/* Search Section */}
      <section>
        <div className="relative">
          <input
            type="text"
            placeholder="ছাত্রের নাম লিখে খুঁজুন..."
            className="w-full p-4 pl-12 rounded-2xl border border-gray-200 shadow-sm focus:ring-2 focus:ring-green-500 focus:border-transparent outline-none transition-all"
            value={searchTerm}
            onChange={(e) => handleSearch(e.target.value)}
          />
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
        </div>

        {searchTerm.length >= 2 && (
          <div className="mt-4 bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
            {loading ? (
              <div className="p-8 text-center text-gray-400">খুঁজছি...</div>
            ) : searchResults.length > 0 ? (
              searchResults.map((student) => (
                <div key={student.id} className="p-4 border-b border-gray-50 flex items-center justify-between active:bg-gray-50 transition-colors">
                  <div>
                    <h3 className="font-bold text-gray-800">{student.student_name}</h3>
                    <p className="text-sm text-gray-500">{student.class_name}</p>
                  </div>
                  <button 
                    onClick={() => makeCall(student)}
                    className="bg-green-100 text-green-700 p-3 rounded-full hover:bg-green-200 transition-colors"
                  >
                    <Phone size={20} fill="currentColor" />
                  </button>
                </div>
              ))
            ) : (
              <div className="p-8 text-center text-gray-500">
                <p>কোনো ছাত্র পাওয়া যায়নি।</p>
                <Link to="/classes" className="text-green-600 text-sm font-bold mt-2 inline-block">নতুন ছাত্র যোগ করুন →</Link>
              </div>
            )}
          </div>
        )}
      </section>

      {/* Recent Calls Section */}
      <section>
        <div className="flex items-center justify-between mb-4 px-1">
          <h2 className="text-lg font-bold flex items-center gap-2">
            <Clock size={20} className="text-green-600" />
            সাম্প্রতিক কলসমূহ
          </h2>
        </div>

        <div className="space-y-3">
          {recentCalls.length > 0 ? (
            recentCalls.map((call) => (
              <div 
                key={call.id} 
                className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer hover:border-green-100"
                onClick={() => makeCall({ student_name: call.student_name, guardian_phone: call.guardian_phone })}
              >
                <div className="flex items-center gap-4">
                  <div className="bg-gray-50 p-3 rounded-2xl text-gray-400">
                    <User size={20} />
                  </div>
                  <div>
                    <h3 className="font-bold text-gray-800">{call.student_name}</h3>
                    <p className="text-sm text-gray-500 font-mono">{call.guardian_phone}</p>
                  </div>
                </div>
                <div className="text-right">
                  <span className="text-[10px] text-gray-400 font-bold uppercase block mb-1">
                    {new Date(call.called_at).toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' })}
                  </span>
                  <div className="bg-green-50 p-2 rounded-full inline-block">
                    <Phone size={16} className="text-green-600" fill="currentColor" />
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-white p-12 text-center rounded-3xl border border-dashed border-gray-200 text-gray-400 flex flex-col items-center">
              <div className="bg-gray-50 p-4 rounded-full mb-4 text-gray-300">
                <Clock size={40} />
              </div>
              <p className="font-medium">এখনও কোনো কল করা হয়নি।</p>
              <p className="text-xs mt-1">ছাত্রদের কল করলে এখানে তালিকা দেখা যাবে।</p>
            </div>
          )}
        </div>
      </section>

      {/* Quick Actions for New Users */}
      {recentCalls.length === 0 && !searchTerm && (
        <section className="bg-green-600 rounded-[2.5rem] p-8 text-white shadow-xl shadow-green-100 relative overflow-hidden">
          <div className="absolute -right-4 -bottom-4 opacity-10 rotate-12">
            <PlusCircle size={160} />
          </div>
          <h3 className="text-xl font-bold mb-2">শুরু করুন!</h3>
          <p className="text-green-50 mb-6 text-sm opacity-90 leading-relaxed">আপনার মাদরাসার ছাত্র ও অভিভাবকদের তথ্য যোগ করুন যাতে দ্রুত যোগাযোগ করতে পারেন।</p>
          <div className="flex gap-3">
            <Link to="/classes" className="bg-white text-green-700 px-6 py-3 rounded-2xl font-bold text-sm shadow-lg active:scale-95 transition-transform">নতুন শ্রেণি খুলুন</Link>
          </div>
        </section>
      )}
    </div>
  );
};

export default Home;

-- 1. Madrasahs Table (Linked to Auth Users)
CREATE TABLE public.madrasahs (
    id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    phone TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. Classes Table
CREATE TABLE public.classes (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    class_name TEXT NOT NULL,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 3. Students Table
CREATE TABLE public.students (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
    CONSTRAINT unique_student_per_madrasah UNIQUE (madrasah_id, class_id, student_name, guardian_phone)
);

-- 4. Recent Calls Table
CREATE TABLE public.recent_calls (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID NOT NULL REFERENCES public.madrasahs(id) ON DELETE CASCADE,
    called_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

