import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Phone, Loader2, CheckCircle } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah }) => {
  const [name, setName] = useState(madrasah?.name || '');
  const [phone, setPhone] = useState(madrasah?.phone || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');

  React.useEffect(() => {
    const getUser = async () => {
      const { data } = await supabase.auth.getUser();
      if (data.user) setEmail(data.user.email || '');
    };
    getUser();
  }, []);

  const handleUpdate = async () => {
    if (!name.trim()) return;
    setSaving(true);
    setSuccess(false);

    const { error } = await supabase
      .from('madrasahs')
      .update({ name, phone })
      .eq('id', madrasah?.id);

    if (!error) {
      setSuccess(true);
      setTimeout(() => setSuccess(false), 3000);
      // Small delay before reloading to show success state
      setTimeout(() => window.location.reload(), 1000);
    } else {
      alert('ত্রুটি: ' + error.message);
    }
    setSaving(false);
  };

  const handleLogout = async () => {
    if (window.confirm('আপনি কি নিশ্চিত যে আপনি লগআউট করতে চান?')) {
      await supabase.auth.signOut();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h2 className="text-2xl font-bold">অ্যাকাউন্ট প্রোফাইল</h2>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 space-y-6">
        <div className="flex flex-col items-center">
          <div className="w-24 h-24 bg-green-600 text-white rounded-full flex items-center justify-center mb-4 shadow-lg shadow-green-100">
            <Building size={48} />
          </div>
          <h3 className="text-2xl font-bold text-gray-800 text-center">{madrasah?.name || 'লোডিং...'}</h3>
          <p className="text-gray-500 font-medium">{email}</p>
        </div>

        <div className="space-y-5 pt-6 border-t border-gray-100">
          <div>
            <label className="block text-sm font-bold text-gray-600 mb-2 flex items-center gap-2">
              <Building size={16} className="text-green-600" /> মাদরাসার নাম
            </label>
            <input 
              type="text" 
              className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-medium"
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="মাদরাসার নাম লিখুন"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-600 mb-2 flex items-center gap-2">
              <Phone size={16} className="text-green-600" /> মাদরাসার ফোন নম্বর
            </label>
            <input 
              type="tel" 
              className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-mono"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              placeholder="01XXXXXXXXX"
            />
          </div>

          <button 
            onClick={handleUpdate}
            disabled={saving || success}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 ${
              success ? 'bg-green-100 text-green-700' : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
            }`}
          >
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'প্রসেসিং হচ্ছে...' : success ? 'সফলভাবে সংরক্ষিত!' : 'তথ্য সংরক্ষণ করুন'}
          </button>
        </div>
      </div>

      <div className="space-y-3">
        <button 
          onClick={handleLogout}
          className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-100 active:scale-95 transition-all"
