          <LogOut size={20} />
          লগআউট করুন
        </button>
      </div>

      <div className="pt-4 text-center">
        <p className="text-xs text-gray-400 font-medium">Madrasah Contact App v1.2.5 • Production Ready</p>
      </div>
    </div>
  );
