import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Phone, Loader2, CheckCircle, Camera, User } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah }) => {
  const [name, setName] = useState(madrasah?.name || '');
  const [phone, setPhone] = useState(madrasah?.phone || '');
  const [avatar, setAvatar] = useState(madrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  React.useEffect(() => {
    const getUser = async () => {
      const { data } = await supabase.auth.getUser();
      if (data.user) setEmail(data.user.email || '');
    };
    getUser();
  }, []);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdate = async () => {
    if (!name.trim()) {
      alert('মাদরাসার নাম অবশ্যই দিতে হবে।');
      return;
    }

    setSaving(true);
    setSuccess(false);

    try {
      const { error } = await supabase
        .from('madrasahs')
        .update({ 
          name: name.trim(), 
          phone: phone.trim(),
          avatar_url: avatar 
        })
        .eq('id', madrasah?.id);

      if (error) throw error;

      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        window.location.reload();
      }, 1500);
    } catch (error: any) {
      alert('ত্রুটি: ' + error.message);
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = async () => {
    if (window.confirm('আপনি কি নিশ্চিত যে আপনি লগআউট করতে চান?')) {
      await supabase.auth.signOut();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold px-1">অ্যাকাউন্ট প্রোফাইল</h2>

      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        {/* প্রোফাইল পিকচার সেকশন */}
        <div className="flex flex-col items-center">
          <div className="relative group">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg shadow-green-100">
              {avatar ? (
                <img src={avatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <Building size={56} className="text-green-600" />
              )}
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-1 right-1 bg-green-600 text-white p-3 rounded-full shadow-lg border-2 border-white hover:bg-green-700 transition-colors"
            >
              <Camera size={20} />
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleImageUpload}
            />
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mt-4">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 font-medium text-sm">{email}</p>
        </div>

        <div className="space-y-5 pt-4 border-t border-gray-50">
          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Building size={16} className="text-green-600" /> মাদরাসার নাম (বাংলায়)
            </label>
            <input 
              type="text" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-medium"
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="মাদরাসার নাম লিখুন"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Phone size={16} className="text-green-600" /> মাদরাসার ফোন নম্বর
            </label>
            <input 
              type="tel" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-mono"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              placeholder="01XXXXXXXXX"
            />
          </div>

          <button 
            onClick={handleUpdate}
            disabled={saving || success}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 ${
              success ? 'bg-green-100 text-green-700' : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
            }`}
          >
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ করা হচ্ছে...' : success ? 'সফলভাবে সংরক্ষিত!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>

      <button 
        onClick={handleLogout}
        className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-100 active:scale-95 transition-all border border-red-100"
      >
        <LogOut size={20} />
        লগআউট করুন
      </button>

      <p className="text-center text-gray-400 text-xs font-medium pt-4">Madrasah Contact App v1.3.0</p>
    </div>
  );
};

export default Account;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { BookOpen, Plus, ChevronRight, Loader2, AlertCircle } from 'lucide-react';
import { ClassRoom } from '../types';

const Classes: React.FC = () => {
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newClassName, setNewClassName] = useState('');
  const [addingError, setAddingError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchClasses();
  }, []);

  const fetchClasses = async () => {
    const { data, error } = await supabase
      .from('classes')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) console.error("Error fetching classes:", error);
    if (data) setClasses(data);
    setLoading(false);
  };

  const addClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setAddingError('');

    if (!newClassName.trim()) return;

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const { data, error } = await supabase.from('classes').insert({
        class_name: newClassName.trim(),
        madrasah_id: session.user.id
      }).select();

      if (error) throw error;

      setNewClassName('');
      setIsAdding(false);
      fetchClasses();
    } catch (err: any) {
      setAddingError(err.message || "ক্লাস যোগ করা সম্ভব হয়নি।");
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center p-20 gap-3">
        <Loader2 className="animate-spin text-green-600" size={40} />
        <p className="text-gray-400 font-medium">লোড হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between px-1">
        <h2 className="text-2xl font-bold">ক্লাসসমূহ</h2>
        <button 
          onClick={() => {
            setIsAdding(!isAdding);
            setAddingError('');
          }}
          className={`${isAdding ? 'bg-gray-100 text-gray-600' : 'bg-green-600 text-white shadow-lg shadow-green-100'} px-4 py-2.5 rounded-2xl flex items-center gap-2 font-bold transition-all active:scale-95`}
        >
          {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
          {isAdding ? 'বাতিল' : 'নতুন ক্লাস'}
        </button>
      </div>

      {isAdding && (
        <form onSubmit={addClass} className="bg-white p-5 rounded-3xl shadow-sm border border-green-100 animate-in slide-in-from-top-4 duration-300">
          <div className="space-y-4">
            <h3 className="font-bold text-gray-700">নতুন ক্লাসের তথ্য</h3>
            <div className="flex gap-2">
              <input
                type="text"
                placeholder="যেমন: ৫ম শ্রেণি"
                className="flex-grow p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-green-500 focus:bg-white transition-all font-medium"
                value={newClassName}
                onChange={(e) => setNewClassName(e.target.value)}
                autoFocus
              />
              <button 
                type="submit" 
                className="bg-green-600 text-white px-6 py-4 rounded-2xl font-bold hover:bg-green-700 transition-colors shadow-lg shadow-green-100"
              >
                যোগ করুন
              </button>
            </div>
            {addingError && (
              <div className="flex items-center gap-2 text-red-600 text-xs font-bold bg-red-50 p-3 rounded-xl border border-red-100">
                <AlertCircle size={16} />
                {addingError}
              </div>
            )}
          </div>
        </form>
      )}

      <div className="grid grid-cols-1 gap-4">
        {classes.length > 0 ? (
          classes.map((cls) => (
            <div 
              key={cls.id}
              onClick={() => navigate(`/classes/${cls.id}`)}
              className="bg-white p-5 rounded-[2rem] border border-gray-50 shadow-sm flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer group hover:border-green-100"
            >
              <div className="flex items-center gap-4">
                <div className="bg-green-50 p-4 rounded-2xl text-green-600 group-hover:bg-green-100 transition-colors">
                  <BookOpen size={28} />
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-800">{cls.class_name}</h3>
                  <p className="text-xs text-gray-400 font-medium">বিস্তারিত দেখতে ক্লিক করুন</p>
                </div>
              </div>
              <div className="bg-gray-50 p-2 rounded-full text-gray-300 group-hover:text-green-500 transition-colors">
                <ChevronRight size={20} />
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200 flex flex-col items-center">
            <BookOpen size={48} className="text-gray-200 mb-4" />
            <p className="text-gray-400 font-bold">এখনও কোনো ক্লাস যোগ করা হয়নি।</p>
            <p className="text-gray-300 text-sm mt-1">শুরু করতে উপরের 'নতুন ক্লাস' বাটনে ক্লিক করুন।</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Classes;

