import React, { useState, useRef } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Phone, Loader2, CheckCircle, Camera, User, Fingerprint, Copy } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah }) => {
  const [name, setName] = useState(madrasah?.name || '');
  const [phone, setPhone] = useState(madrasah?.phone || '');
  const [avatar, setAvatar] = useState(madrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const [uid, setUid] = useState(madrasah?.id || '');
  const fileInputRef = useRef<HTMLInputElement>(null);

  React.useEffect(() => {
    const getUser = async () => {
      const { data } = await supabase.auth.getUser();
      if (data.user) {
        setEmail(data.user.email || '');
        setUid(data.user.id);
      }
    };
    getUser();
  }, []);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdate = async () => {
    if (!name.trim()) {
      alert('মাদরাসার নাম অবশ্যই দিতে হবে।');
      return;
    }

    setSaving(true);
    setSuccess(false);

    try {
      const { error } = await supabase
        .from('madrasahs')
        .update({ 
          name: name.trim(), 
          phone: phone.trim(),
          avatar_url: avatar 
        })
        .eq('id', madrasah?.id);

      if (error) throw error;

      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        window.location.reload();
      }, 1500);
    } catch (error: any) {
      alert('ত্রুটি: ' + error.message);
    } finally {
      setSaving(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert('আইডি কপি করা হয়েছে!');
  };

  const handleLogout = async () => {
    if (window.confirm('আপনি কি নিশ্চিত যে আপনি লগআউট করতে চান?')) {
      await supabase.auth.signOut();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold px-1">অ্যাকাউন্ট প্রোফাইল</h2>

      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        {/* প্রোফাইল পিকচার সেকশন */}
        <div className="flex flex-col items-center">
          <div className="relative group">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg shadow-green-100">
              {avatar ? (
                <img src={avatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <Building size={56} className="text-green-600" />
              )}
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-1 right-1 bg-green-600 text-white p-3 rounded-full shadow-lg border-2 border-white hover:bg-green-700 transition-colors"
            >
              <Camera size={20} />
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleImageUpload}
            />
          </div>
          <h3 className="text-2xl font-bold text-gray-800 mt-4">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 font-medium text-sm">{email}</p>
        </div>

        <div className="space-y-5 pt-4 border-t border-gray-50">
          {/* ইউজার আইডি (Read-only) */}
          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Fingerprint size={16} className="text-blue-600" /> ইউজার আইডি (UID)
            </label>
            <div className="relative group">
              <input 
                type="text" 
                readOnly
                className="w-full p-4 border border-gray-100 rounded-2xl bg-blue-50/50 text-gray-400 font-mono text-[10px] cursor-not-allowed outline-none"
                value={uid}
              />
              <button 
                onClick={() => copyToClipboard(uid)}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-2 hover:bg-white rounded-xl text-gray-400 hover:text-blue-600 transition-colors"
                title="কপি করুন"
              >
                <Copy size={16} />
              </button>
            </div>
            <p className="text-[10px] text-gray-400 mt-1 ml-1">* এটি আপনার সিস্টেম আইডি, যা এডিট করা সম্ভব নয়।</p>
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Building size={16} className="text-green-600" /> মাদরাসার নাম (বাংলায়)
            </label>
            <input 
              type="text" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-medium"
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="মাদরাসার নাম লিখুন"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Phone size={16} className="text-green-600" /> মাদরাসার ফোন নম্বর
            </label>
            <input 
              type="tel" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-mono"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              placeholder="01XXXXXXXXX"
            />
          </div>

          <button 
            onClick={handleUpdate}
            disabled={saving || success}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 ${
              success ? 'bg-green-100 text-green-700' : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
            }`}
          >
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ করা হচ্ছে...' : success ? 'সফলভাবে সংরক্ষিত!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>

      <button 
        onClick={handleLogout}
        className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-100 active:scale-95 transition-all border border-red-100"
      >
        <LogOut size={20} />
        লগআউট করুন
      </button>

      <p className="text-center text-gray-400 text-xs font-medium pt-4">Madrasah Contact App v1.3.1</p>
    </div>
  );
};

export default Account;

-- ১. মাদ্রাসা টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.madrasahs (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    name TEXT NOT NULL DEFAULT 'নতুন মাদ্রাসা',
    phone TEXT,
    avatar_url TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ২. ক্লাস টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.classes (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    class_name TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৩. ছাত্র টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৪. সাম্প্রতিক কল টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    called_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৫. আরএলএস (RLS) সক্রিয় করা
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- ৬. মাদরাসা পলিসি
CREATE POLICY "মাদরাসা শুধুমাত্র নিজের প্রোফাইল দেখতে পারবে" ON public.madrasahs
    FOR SELECT USING (auth.uid() = id);
CREATE POLICY "মাদরাসা নিজের প্রোফাইল আপডেট করতে পারবে" ON public.madrasahs
    FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "মাদরাসা প্রোফাইল ইনসার্ট" ON public.madrasahs
    FOR INSERT WITH CHECK (auth.uid() = id);

-- ৭. ক্লাস পলিসি
CREATE POLICY "মাদরাসা শুধুমাত্র নিজের ক্লাস দেখতে পারবে" ON public.classes
    FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস যোগ করতে পারবে" ON public.classes
    FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস আপডেট করতে পারবে" ON public.classes
    FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস ডিলিট করতে পারবে" ON public.classes
    FOR DELETE USING (madrasah_id = auth.uid());

-- ৮. ছাত্র পলিসি
CREATE POLICY "মাদরাসা শুধুমাত্র নিজের ছাত্র দেখতে পারবে" ON public.students
    FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ছাত্র যোগ করতে পারবে" ON public.students
    FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ছাত্র আপডেট করতে পারবে" ON public.students
    FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ছাত্র ডিলিট করতে পারবে" ON public.students
    FOR DELETE USING (madrasah_id = auth.uid());

-- ৯. কল রেকর্ড পলিসি
CREATE POLICY "মাদরাসা নিজের কল রেকর্ড দেখতে পারবে" ON public.recent_calls
    FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা কল রেকর্ড যোগ করতে পারবে" ON public.recent_calls
    FOR INSERT WITH CHECK (madrasah_id = auth.uid());

-- ১০. নতুন ইউজার রেজিস্ট্রেশনের সাথে প্রোফাইল অটো-তৈরির ফাংশন
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO public.madrasahs (id, name)
    VALUES (new.id, 'নতুন মাদ্রাসা');
    RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- ১১. ট্রিগার সক্রিয় করা (যদি আগে থেকে না থাকে)
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
    AFTER INSERT ON auth.users
    FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Phone, Loader2, CheckCircle, Camera, Fingerprint, Copy } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const [uid, setUid] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const getUser = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setEmail(user.email || '');
        setUid(user.id);

        // যদি প্রপস থেকে ডাটা না আসে, তাহলে সরাসরি ডাটাবেস থেকে আবার চেক করি
        if (!initialMadrasah) {
          const { data } = await supabase
            .from('madrasahs')
            .select('*')
            .eq('id', user.id)
            .single();
          if (data) {
            setName(data.name);
            setPhone(data.phone || '');
            setAvatar(data.avatar_url || '');
          }
        }
      }
    };
    getUser();
  }, [initialMadrasah]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { // 2MB limit
        alert('ছবিটি ২ মেগাবাইটের চেয়ে বড়। অনুগ্রহ করে ছোট ছবি ব্যবহার করুন।');
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdate = async () => {
    if (!name.trim()) {
      alert('মাদরাসার নাম অবশ্যই দিতে হবে।');
      return;
    }

    setSaving(true);
    setSuccess(false);

    try {
      // বর্তমান সেশন চেক করা
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const { error } = await supabase
        .from('madrasahs')
        .upsert({ 
          id: user.id, // নিশ্চিত করা যে সঠিক আইডি ব্যবহার হচ্ছে
          name: name.trim(), 
          phone: phone.trim(),
          avatar_url: avatar 
        });

      if (error) throw error;

      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        // রিফ্রেশ করার বদলে সেশন আপডেট হতে সময় দিন
        window.location.reload();
      }, 1500);
    } catch (error: any) {
      console.error("Update error:", error);
      alert('ত্রুটি: ' + (error.message || 'সংরক্ষণ করা সম্ভব হয়নি'));
    } finally {
      setSaving(false);
    }
  };

  const copyToClipboard = (text: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    alert('আইডি কপি করা হয়েছে!');
  };

  const handleLogout = async () => {
    if (window.confirm('আপনি কি নিশ্চিত যে আপনি লগআউট করতে চান?')) {
      await supabase.auth.signOut();
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold px-1 text-gray-800">অ্যাকাউন্ট প্রোফাইল</h2>

      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        {/* প্রোফাইল পিকচার সেকশন */}
        <div className="flex flex-col items-center">
          <div className="relative group">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg shadow-green-100">
              {avatar ? (
                <img src={avatar} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <Building size={56} className="text-green-600 opacity-40" />
              )}
            </div>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-1 right-1 bg-green-600 text-white p-3 rounded-full shadow-lg border-2 border-white hover:bg-green-700 transition-all active:scale-90"
              title="ছবি পরিবর্তন করুন"
            >
              <Camera size={20} />
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleImageUpload}
            />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mt-4 text-center">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 font-medium text-sm">{email}</p>
        </div>

        <div className="space-y-5 pt-4 border-t border-gray-50">
          {/* ইউজার আইডি (Read-only) */}
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Fingerprint size={14} className="text-blue-600" /> আপনার সিস্টেম আইডি (UID)
            </label>
            <div className="relative group">
              <input 
                type="text" 
                readOnly
                className="w-full p-4 border border-gray-100 rounded-2xl bg-blue-50/30 text-gray-400 font-mono text-[10px] cursor-not-allowed outline-none pr-12"
                value={uid}
              />
              <button 
                onClick={() => copyToClipboard(uid)}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-2 hover:bg-white rounded-xl text-gray-400 hover:text-blue-600 transition-colors"
                title="কপি করুন"
              >
                <Copy size={16} />
              </button>
            </div>
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Building size={16} className="text-green-600" /> মাদরাসার নাম (বাংলায়)
            </label>
            <input 
              type="text" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-medium text-gray-700"
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="মাদরাসার নাম লিখুন"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-500 mb-2 flex items-center gap-2 ml-1">
              <Phone size={16} className="text-green-600" /> যোগাযোগ নম্বর (মোবাইল)
            </label>
            <input 
              type="tel" 
              className="w-full p-4 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none bg-gray-50 focus:bg-white transition-all font-mono text-gray-700"
              value={phone}
              onChange={e => setPhone(e.target.value)}
              placeholder="01XXXXXXXXX"
            />
          </div>

          <button 
            onClick={handleUpdate}
            disabled={saving || success}
            className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all shadow-lg active:scale-95 mt-4 ${
              success ? 'bg-green-100 text-green-700' : 'bg-green-600 text-white hover:bg-green-700 shadow-green-100'
            }`}
          >
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ করা হচ্ছে...' : success ? 'সফলভাবে সংরক্ষিত!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>

      <button 
        onClick={handleLogout}
        className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-100 active:scale-95 transition-all border border-red-100 mt-4"
      >
        <LogOut size={20} />
        লগআউট করুন
      </button>

      <p className="text-center text-gray-400 text-[10px] font-medium pt-4 uppercase tracking-widest">Madrasah Contact App v1.3.2</p>
    </div>
  );
};

export default Account;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { BookOpen, Plus, ChevronRight, Loader2, AlertCircle } from 'lucide-react';
import { ClassRoom } from '../types';

const Classes: React.FC = () => {
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newClassName, setNewClassName] = useState('');
  const [addingError, setAddingError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    fetchClasses();
  }, []);

  const fetchClasses = async () => {
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('classes')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setClasses(data);
    } catch (err) {
      console.error("Error fetching classes:", err);
    } finally {
      setLoading(false);
    }
  };

  const addClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setAddingError('');

    const className = newClassName.trim();
    if (!className) {
      setAddingError('শ্রেণির নাম খালি রাখা যাবে না।');
      return;
    }

    setIsSubmitting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি। অনুগ্রহ করে আবার লগইন করুন।");

      const { error } = await supabase.from('classes').insert({
        class_name: className,
        madrasah_id: user.id
      });

      if (error) throw error;

      setNewClassName('');
      setIsAdding(false);
      await fetchClasses(); // নতুন ডাটা ফেচ করুন
    } catch (err: any) {
      console.error("Add class error:", err);
      setAddingError(err.message || "ক্লাস যোগ করা সম্ভব হয়নি। ডাটাবেস সমস্যা হতে পারে।");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center p-20 gap-3">
        <Loader2 className="animate-spin text-green-600" size={40} />
        <p className="text-gray-400 font-medium">ক্লাস লোড হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex items-center justify-between px-1">
        <h2 className="text-2xl font-bold text-gray-800">ক্লাসসমূহ</h2>
        <button 
          onClick={() => {
            setIsAdding(!isAdding);
            setAddingError('');
            setNewClassName('');
          }}
          className={`${isAdding ? 'bg-gray-100 text-gray-600' : 'bg-green-600 text-white shadow-lg shadow-green-100'} px-4 py-2.5 rounded-2xl flex items-center gap-2 font-bold transition-all active:scale-95`}
          disabled={isSubmitting}
        >
          {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
          {isAdding ? 'বাতিল' : 'নতুন ক্লাস'}
        </button>
      </div>

      {isAdding && (
        <form onSubmit={addClass} className="bg-white p-5 rounded-3xl shadow-sm border border-green-100 animate-in slide-in-from-top-4 duration-300">
          <div className="space-y-4">
            <h3 className="font-bold text-gray-700 text-sm">নতুন ক্লাসের নাম লিখুন</h3>
            <div className="flex gap-2">
              <input
                type="text"
                placeholder="যেমন: নূরানী ১ম বিভাগ"
                className="flex-grow p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-green-500 focus:bg-white transition-all font-medium"
                value={newClassName}
                onChange={(e) => setNewClassName(e.target.value)}
                autoFocus
                disabled={isSubmitting}
              />
              <button 
                type="submit" 
                disabled={isSubmitting}
                className="bg-green-600 text-white px-6 py-4 rounded-2xl font-bold hover:bg-green-700 transition-colors shadow-lg shadow-green-100 flex items-center justify-center disabled:opacity-70"
              >
                {isSubmitting ? <Loader2 className="animate-spin" size={20} /> : 'যোগ'}
              </button>
            </div>
            {addingError && (
              <div className="flex items-center gap-2 text-red-600 text-xs font-bold bg-red-50 p-3 rounded-xl border border-red-100">
                <AlertCircle size={16} />
                {addingError}
              </div>
            )}
          </div>
        </form>
      )}

      <div className="grid grid-cols-1 gap-4">
        {classes.length > 0 ? (
          classes.map((cls) => (
            <div 
              key={cls.id}
              onClick={() => navigate(`/classes/${cls.id}`)}
              className="bg-white p-5 rounded-[2rem] border border-gray-50 shadow-sm flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer group hover:border-green-100"
            >
              <div className="flex items-center gap-4">
                <div className="bg-green-50 p-4 rounded-2xl text-green-600 group-hover:bg-green-100 transition-colors">
                  <BookOpen size={28} />
                </div>
                <div>
                  <h3 className="font-bold text-lg text-gray-800">{cls.class_name}</h3>
                  <p className="text-xs text-gray-400 font-medium">ছাত্র তালিকা দেখতে ক্লিক করুন</p>
                </div>
              </div>
              <div className="bg-gray-50 p-2 rounded-full text-gray-300 group-hover:text-green-500 transition-colors">
                <ChevronRight size={20} />
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-20 bg-white rounded-[2.5rem] border border-dashed border-gray-200 flex flex-col items-center">
            <BookOpen size={48} className="text-gray-100 mb-4" />
            <p className="text-gray-400 font-bold">এখনও কোনো ক্লাস যোগ করা হয়নি।</p>
            <p className="text-gray-300 text-sm mt-1">শুরু করতে উপরের 'নতুন ক্লাস' বাটনে ক্লিক করুন।</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Classes;

payload.text:
অবশ্যই! আপনার সুপাবাস (Supabase) ডাটাবেসটি সঠিকভাবে কাজ করার জন্য নিচের SQL কোডটি কপি করে সুপাবাস ড্যাশবোর্ডের **SQL Editor**-এ গিয়ে **Run** বাটনে ক্লিক করুন। 

এই কোডটি প্রয়োজনীয় সব টেবিল তৈরি করবে, **RLS (Row Level Security)** চালু করবে এবং নতুন ইউজার রেজিস্ট্রেশন করলে স্বয়ংক্রিয়ভাবে মাদরাসা প্রোফাইল তৈরি করার ট্রিগার (Trigger) সেটআপ করে দিবে।

```sql
-- ১. মাদ্রাসা টেবিল তৈরি (মাদরাসা প্রোফাইল স্টোর করার জন্য)
CREATE TABLE IF NOT EXISTS public.madrasahs (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    name TEXT NOT NULL DEFAULT 'নতুন মাদ্রাসা',
    phone TEXT,
    avatar_url TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ২. ক্লাস টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.classes (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    class_name TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৩. ছাত্র টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৪. সাম্প্রতিক কল টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    called_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৫. আরএলএস (RLS) সক্রিয় করা (নিরাপত্তার জন্য অত্যন্ত জরুরি)
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- ৬. মাদরাসা (Profiles) আরএলএস পলিসি
CREATE POLICY "মাদরাসা নিজের প্রোফাইল দেখতে পারবে" ON public.madrasahs FOR SELECT USING (auth.uid() = id);
CREATE POLICY "মাদরাসা নিজের প্রোফাইল আপডেট করতে পারবে" ON public.madrasahs FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "মাদরাসা নিজের প্রোফাইল ইনসার্ট করতে পারবে" ON public.madrasahs FOR INSERT WITH CHECK (auth.uid() = id);

-- ৭. ক্লাস টেবিল আরএলএস পলিসি
CREATE POLICY "মাদরাসা নিজের ক্লাস দেখতে পারবে" ON public.classes FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস যোগ করতে পারবে" ON public.classes FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস আপডেট করতে পারবে" ON public.classes FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "মাদরাসা ক্লাস মুছতে পারবে" ON public.classes FOR DELETE USING (madrasah_id = auth.uid());

-- ৮. ছাত্র টেবিল আরএলএস পলিসি
CREATE POLICY "মাদরাসা নিজের ছাত্র দেখতে পারবে" ON public.students FOR SELECT USING (madrasah_id = auth.uid());
