import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Phone, Loader2, CheckCircle, Camera, Fingerprint, Copy } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const [uid, setUid] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const getUser = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setEmail(user.email || '');
        setUid(user.id);

        // Fetch latest data to ensure UI sync
        const { data } = await supabase
          .from('madrasahs')
          .select('*')
          .eq('id', user.id)
          .single();
        if (data) {
          setName(data.name);
          setPhone(data.phone || '');
          setAvatar(data.avatar_url || '');
        }
      }
    };
    getUser();
  }, [initialMadrasah]);

  const handleUpdate = async () => {
    if (!name.trim()) {
      alert('মাদরাসার নাম অবশ্যই দিতে হবে।');
      return;
    }

    setSaving(true);
    setSuccess(false);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      // Use upsert to handle both first-time insert and updates
      const { error } = await supabase
        .from('madrasahs')
        .upsert({ 
          id: user.id, 
          name: name.trim(), 
          phone: phone.trim(),
          avatar_url: avatar 
        }, { onConflict: 'id' });

      if (error) throw error;

      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        window.location.reload(); // Refresh to update global layout name
      }, 1000);
    } catch (error: any) {
      console.error("Update error:", error);
