CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    called_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৫. আরএলএস (RLS) সক্রিয় করা
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- ৬. মাদরাসা প্রোফাইল পলিসি (পুরোনো থাকলে ডিলিট করে নতুন তৈরি)
DO $$ BEGIN
    DROP POLICY IF EXISTS "madrasah_select_own" ON public.madrasahs;
    DROP POLICY IF EXISTS "madrasah_update_own" ON public.madrasahs;
    DROP POLICY IF EXISTS "madrasah_insert_own" ON public.madrasahs;
EXCEPTION WHEN undefined_table THEN
    -- Table doesn't exist yet, which shouldn't happen here
END $$;

CREATE POLICY "madrasah_select_own" ON public.madrasahs FOR SELECT USING (auth.uid() = id);
CREATE POLICY "madrasah_update_own" ON public.madrasahs FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "madrasah_insert_own" ON public.madrasahs FOR INSERT WITH CHECK (auth.uid() = id);

