    DROP POLICY IF EXISTS "classes_update_own" ON public.classes;
    DROP POLICY IF EXISTS "classes_delete_own" ON public.classes;
END $$;

CREATE POLICY "classes_select_own" ON public.classes FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "classes_insert_own" ON public.classes FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "classes_update_own" ON public.classes FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "classes_delete_own" ON public.classes FOR DELETE USING (madrasah_id = auth.uid());

-- ৮. ছাত্র পলিসি
DO $$ BEGIN
