    DROP POLICY IF EXISTS "students_insert_own" ON public.students;
    DROP POLICY IF EXISTS "students_update_own" ON public.students;
    DROP POLICY IF EXISTS "students_delete_own" ON public.students;
END $$;

CREATE POLICY "students_select_own" ON public.students FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "students_insert_own" ON public.students FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "students_update_own" ON public.students FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "students_delete_own" ON public.students FOR DELETE USING (madrasah_id = auth.uid());

-- ৯. সাম্প্রতিক কল পলিসি
DO $$ BEGIN
