CREATE POLICY "recent_calls_insert_own" ON public.recent_calls FOR INSERT WITH CHECK (madrasah_id = auth.uid());

-- ১০. নতুন ইউজার হ্যান্ডলার এবং ট্রিগার
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO public.madrasahs (id, name)
    VALUES (new.id, 'নতুন মাদ্রাসা')
    ON CONFLICT (id) DO NOTHING;
    RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
    AFTER INSERT ON auth.users
    FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Loader2, CheckCircle, Camera } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadProfile = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setEmail(user.email || '');
        const { data } = await supabase.from('madrasahs').select('*').eq('id', user.id).single();
        if (data) {
          setName(data.name);
          setPhone(data.phone || '');
          setAvatar(data.avatar_url || '');
        }
      }
    };
    loadProfile();
  }, []);

  const handleUpdate = async () => {
    if (!name.trim()) return alert('মাদরাসার নাম দিন।');
    setSaving(true);
    setSuccess(false);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const { error } = await supabase.from('madrasahs').upsert({ 
        id: user.id, 
        name: name.trim(), 
        phone: phone.trim(),
        avatar_url: avatar 
      });

      if (error) throw error;
      setSuccess(true);
      setTimeout(() => setSuccess(false), 2000);
    } catch (err: any) {
      alert('ত্রুটি: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-6 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold text-gray-800">অ্যাকাউন্ট প্রোফাইল</h2>
      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        <div className="flex flex-col items-center">
          <div className="relative">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg">
              {avatar ? <img src={avatar} className="w-full h-full object-cover" /> : <Building size={56} className="text-green-600 opacity-40" />}
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-1 right-1 bg-green-600 text-white p-2.5 rounded-full shadow-lg border-2 border-white">
              <Camera size={18} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImage} />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mt-4">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 text-sm">{email}</p>
        </div>

        <div className="space-y-4 pt-4 border-t border-gray-50">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">মাদরাসার নাম (বাংলায়)</label>
            <input type="text" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={name} onChange={e => setName(e.target.value)} />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">যোগাযোগ নম্বর</label>
            <input type="tel" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={phone} onChange={e => setPhone(e.target.value)} placeholder="01XXXXXXXXX" />
          </div>
          <button onClick={handleUpdate} disabled={saving} className="w-full py-4 bg-green-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg">
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ হচ্ছে...' : success ? 'সফল!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>
      <button onClick={() => supabase.auth.signOut()} className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 border border-red-100">
        লগআউট
      </button>
    </div>
  );
};

export default Account;

