import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './lib/supabase';
import Layout from './components/Layout';
import Home from './pages/Home';
import Classes from './pages/Classes';
import Students from './pages/Students';
import Account from './pages/Account';
import Login from './pages/Login';
import ImportData from './pages/ImportData';
import { AuthState, Madrasah } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    loading: true,
    madrasah: null,
  });

  const fetchMadrasahProfile = async (userId: string): Promise<Madrasah | null> => {
    // প্রথমেই চেক করি প্রোফাইল আছে কি না
    let { data, error } = await supabase
      .from('madrasahs')
      .select('*')
      .eq('id', userId)
      .single();

    // যদি প্রোফাইল না থাকে, তবে একটি তৈরি করি (ট্রিগার মিস করলে ব্যাকআপ)
    if (error || !data) {
      const { data: newData, error: insertError } = await supabase
        .from('madrasahs')
        .upsert({ id: userId, name: 'নতুন মাদরাসা' })
        .select('*')
        .single();
      return newData;
    }
    return data;
  };

  useEffect(() => {
    const checkUser = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const madrasah = await fetchMadrasahProfile(session.user.id);
          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err) {
        setAuth(prev => ({ ...prev, loading: false }));
      }
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
        const madrasah = await fetchMadrasahProfile(session.user.id);
        setAuth({ user: session.user, madrasah, loading: false });
      } else {
        setAuth({ user: null, madrasah: null, loading: false });
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (auth.loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-green-50 text-green-600 font-bold">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          <p>লোড হচ্ছে...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {auth.user ? (
          <Route element={<Layout madrasahName={auth.madrasah?.name || 'মাদরাসা'} />}>
            <Route path="/" element={<Home />} />
            <Route path="/classes" element={<Classes />} />
            <Route path="/classes/:classId" element={<Students />} />
            <Route path="/account" element={<Account madrasah={auth.madrasah} />} />
            <Route path="/import" element={<ImportData />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        ) : (
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Loader2, CheckCircle, Camera, Upload } from 'lucide-react';
import { Madrasah } from '../types';
import { Link } from 'react-router-dom';

interface AccountProps {
  madrasah: Madrasah | null;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadProfile = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        setEmail(user.email || '');
        const { data } = await supabase.from('madrasahs').select('*').eq('id', user.id).single();
        if (data) {
          setName(data.name);
          setPhone(data.phone || '');
          setAvatar(data.avatar_url || '');
        }
      }
    };
    loadProfile();
  }, []);

  const handleUpdate = async () => {
    if (!name.trim()) return alert('মাদরাসার নাম দিন।');
    setSaving(true);
    setSuccess(false);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const { error } = await supabase.from('madrasahs').upsert({ 
        id: user.id, 
        name: name.trim(), 
        phone: phone.trim(),
        avatar_url: avatar 
      });

      if (error) throw error;
      setSuccess(true);
      setTimeout(() => setSuccess(false), 2000);
    } catch (err: any) {
      alert('ত্রুটি: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-6 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold text-gray-800">অ্যাকাউন্ট প্রোফাইল</h2>
      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        <div className="flex flex-col items-center">
          <div className="relative">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg">
              {avatar ? <img src={avatar} className="w-full h-full object-cover" /> : <Building size={56} className="text-green-600 opacity-40" />}
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-1 right-1 bg-green-600 text-white p-2.5 rounded-full shadow-lg border-2 border-white">
              <Camera size={18} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImage} />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mt-4">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 text-sm">{email}</p>
        </div>

        <div className="space-y-4 pt-4 border-t border-gray-50">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">মাদরাসার নাম (বাংলায়)</label>
            <input type="text" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={name} onChange={e => setName(e.target.value)} />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">যোগাযোগ নম্বর</label>
            <input type="tel" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={phone} onChange={e => setPhone(e.target.value)} placeholder="01XXXXXXXXX" />
          </div>

          <Link to="/import" className="flex items-center justify-center gap-2 py-3 bg-gray-50 text-gray-600 rounded-2xl border border-gray-100 text-sm font-bold">
            <Upload size={18} /> একসাথে অনেক ছাত্র যোগ করুন
          </Link>

          <button onClick={handleUpdate} disabled={saving} className="w-full py-4 bg-green-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg">
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ হচ্ছে...' : success ? 'সফল!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>
      <button onClick={() => supabase.auth.signOut()} className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 border border-red-100">
        <LogOut size={20} /> লগআউট
      </button>
    </div>
  );
};

export default Account;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { BookOpen, Plus, ChevronRight, Loader2, AlertCircle } from 'lucide-react';
import { ClassRoom } from '../types';

const Classes: React.FC = () => {
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newClassName, setNewClassName] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchClasses();
  }, []);

  const fetchClasses = async () => {
    try {
      setLoading(true);
      const { data, error: fetchError } = await supabase
        .from('classes')
        .select('*')
        .order('created_at', { ascending: false });

      if (fetchError) throw fetchError;
      setClasses(data || []);
    } catch (err: any) {
      console.error("Fetch classes error:", err);
      setError("ডাটাবেস টেবিল খুঁজে পাওয়া যায়নি। অনুগ্রহ করে SQL স্ক্রিপ্টটি আবার রান করুন।");
    } finally {
      setLoading(false);
    }
  };

  const addClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const name = newClassName.trim();
    if (!name) return;

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("সেশন নেই");

      const { error: insError } = await supabase.from('classes').insert({
        class_name: name,
        madrasah_id: user.id
      });

      if (insError) throw insError;

      setNewClassName('');
      setIsAdding(false);
      fetchClasses();
    } catch (err: any) {
      setError(err.message || "ক্লাস যোগ করা যায়নি।");
    }
  };

  if (loading) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-green-600" /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold">ক্লাসসমূহ</h2>
        <button onClick={() => setIsAdding(!isAdding)} className="bg-green-600 text-white p-3 rounded-2xl flex items-center gap-2 font-bold shadow-lg">
          <Plus size={20} /> নতুন
        </button>
      </div>

      {error && (
        <div className="bg-red-50 text-red-600 p-4 rounded-2xl border border-red-100 flex items-start gap-3">
          <AlertCircle className="flex-shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      {isAdding && (
        <form onSubmit={addClass} className="bg-white p-5 rounded-3xl border border-green-100 shadow-sm space-y-4">
          <input 
            className="w-full p-4 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-green-500" 
            placeholder="শ্রেণির নাম (যেমন: ১ম শ্রেণি)" 
            value={newClassName}
            onChange={e => setNewClassName(e.target.value)}
            autoFocus
          />
          <button type="submit" className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold">যোগ করুন</button>
        </form>
      )}

      <div className="space-y-4">
        {classes.length > 0 ? (
          classes.map(cls => (
            <div key={cls.id} onClick={() => navigate(`/classes/${cls.id}`)} className="bg-white p-5 rounded-[2rem] border border-gray-50 shadow-sm flex items-center justify-between cursor-pointer active:scale-95 transition-all">
              <div className="flex items-center gap-4">
                <div className="bg-green-50 p-4 rounded-2xl text-green-600"><BookOpen /></div>
                <h3 className="font-bold text-lg">{cls.class_name}</h3>
              </div>
              <ChevronRight className="text-gray-300" />
            </div>
          ))
        ) : !isAdding && (
          <div className="text-center py-20 bg-white rounded-[2rem] border border-dashed border-gray-200">
            <p className="text-gray-400">কোনো ক্লাস খুঁজে পাওয়া যায়নি।</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Classes;

export interface Madrasah {
  id: string;
  name: string;
  phone?: string;
  avatar_url?: string;
  created_at: string;
}

export interface ClassRoom {
  id: string;
  class_name: string;
  madrasah_id: string;
}

export interface Student {
  id: string;
  student_name: string;
  guardian_phone: string;
  roll_number: number;
  class_id: string;
  madrasah_id: string;
  class_name?: string;
}

export interface RecentCall {
  id: string;
  student_id: string | null;
  student_name: string;
  guardian_phone: string;
  called_at: string;
}

export interface AuthState {
  user: any;
  loading: boolean;
  madrasah: Madrasah | null;
}

-- ১. মাদরাসা (প্রোফাইল) টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.madrasahs (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    name TEXT NOT NULL DEFAULT 'নতুন মাদ্রাসা',
    phone TEXT,
    avatar_url TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ২. ক্লাস টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.classes (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    class_name TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৩. ছাত্র টেবিল তৈরি (রোল নম্বর সহ)
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    roll_number INTEGER DEFAULT 0,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৪. সাম্প্রতিক কল টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    called_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৫. আরএলএস (RLS) সক্রিয় করা
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- ৬. সিকিউরিটি পলিসি সমূহ
CREATE POLICY "m_select" ON public.madrasahs FOR SELECT USING (auth.uid() = id);
CREATE POLICY "m_update" ON public.madrasahs FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "m_insert" ON public.madrasahs FOR INSERT WITH CHECK (auth.uid() = id);

CREATE POLICY "c_select" ON public.classes FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "c_insert" ON public.classes FOR INSERT WITH CHECK (madrasah_id = auth.uid());

CREATE POLICY "s_select" ON public.students FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "s_insert" ON public.students FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "s_update" ON public.students FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "s_delete" ON public.students FOR DELETE USING (madrasah_id = auth.uid());

CREATE POLICY "r_select" ON public.recent_calls FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "r_insert" ON public.recent_calls FOR INSERT WITH CHECK (madrasah_id = auth.uid());

-- ১০. নতুন ইউজার হ্যান্ডলার
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO public.madrasahs (id, name)
    VALUES (new.id, 'নতুন মাদ্রাসা')
    ON CONFLICT (id) DO NOTHING;
    RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
    AFTER INSERT ON auth.users
    FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './lib/supabase';
import Layout from './components/Layout';
import Home from './pages/Home';
import Classes from './pages/Classes';
import Students from './pages/Students';
import Account from './pages/Account';
import Login from './pages/Login';
import { AuthState, Madrasah } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    loading: true,
    madrasah: null,
  });

  const fetchMadrasahProfile = async (userId: string): Promise<Madrasah | null> => {
    let { data, error } = await supabase
      .from('madrasahs')
      .select('*')
      .eq('id', userId)
      .single();

    if (error || !data) {
      const { data: newData } = await supabase
        .from('madrasahs')
        .upsert({ id: userId, name: 'নতুন মাদরাসা' })
        .select('*')
        .single();
      return newData;
    }
    return data;
  };

  useEffect(() => {
    const checkUser = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const madrasah = await fetchMadrasahProfile(session.user.id);
          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err) {
        setAuth(prev => ({ ...prev, loading: false }));
      }
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
        const madrasah = await fetchMadrasahProfile(session.user.id);
        setAuth({ user: session.user, madrasah, loading: false });
      } else {
        setAuth({ user: null, madrasah: null, loading: false });
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (auth.loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-green-50 text-green-600 font-bold">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          <p>লোড হচ্ছে...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {auth.user ? (
          <Route element={<Layout madrasahName={auth.madrasah?.name || 'মাদরাসা'} />}>
            <Route path="/" element={<Home />} />
            <Route path="/classes" element={<Classes />} />
            <Route path="/classes/:classId" element={<Students />} />
            <Route path="/account" element={<Account madrasah={auth.madrasah} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        ) : (
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

export default App;

