import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { Phone, Plus, X, User, Edit2, ArrowLeft, Loader2, Hash } from 'lucide-react';
import { Student } from '../types';

const Students: React.FC = () => {
  const { classId } = useParams();
  const navigate = useNavigate();
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showDetails, setShowDetails] = useState<Student | null>(null);
  const [className, setClassName] = useState('');

  const [editId, setEditId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', phone: '', roll: '' });

  useEffect(() => {
    fetchClassAndStudents();
  }, [classId]);

  const fetchClassAndStudents = async () => {
    if (!classId) return;

    const [classRes, studentRes] = await Promise.all([
      supabase.from('classes').select('class_name').eq('id', classId).single(),
      supabase.from('students')
        .select('*')
        .eq('class_id', classId)
        .order('roll_number', { ascending: true }) // রোল অনুযায়ী সিরিয়াল ছোট থেকে বড়
    ]);

    if (classRes.data) setClassName(classRes.data.class_name);
    if (studentRes.data) setStudents(studentRes.data);
    setLoading(false);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone) return;

    const { data: userData } = await supabase.auth.getUser();
    if (!userData.user || !classId) return;

    const payload = {
      student_name: formData.name,
      guardian_phone: formData.phone,
      roll_number: parseInt(formData.roll) || 0,
      class_id: classId,
      madrasah_id: userData.user.id
    };

    if (editId) {
      await supabase.from('students').update(payload).eq('id', editId);
    } else {
      await supabase.from('students').insert(payload);
    }

    setShowModal(false);
    setEditId(null);
    setFormData({ name: '', phone: '', roll: '' });
    fetchClassAndStudents();
  };

  const startEdit = (student: Student) => {
    setEditId(student.id);
    setFormData({ 
      name: student.student_name, 
      phone: student.guardian_phone, 
      roll: student.roll_number?.toString() || '' 
    });
    setShowDetails(null);
    setShowModal(true);
  };

  const makeCall = async (student: Student) => {
    await supabase.from('recent_calls').insert({
      student_id: student.id,
      student_name: student.student_name,
      guardian_phone: student.guardian_phone,
      madrasah_id: student.madrasah_id
    });
    window.location.href = `tel:${student.guardian_phone}`;
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-green-600" /></div>;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/classes')} className="text-gray-500 hover:bg-gray-100 p-2 rounded-full transition-colors"><ArrowLeft /></button>
        <h2 className="text-2xl font-bold">{className}</h2>
      </div>

      <div className="space-y-3">
        {students.length > 0 ? (
          students.map((student) => (
            <div 
              key={student.id} 
              onClick={() => setShowDetails(student)}
              className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between active:bg-gray-50 transition-colors cursor-pointer"
            >
              <div className="flex items-center gap-3">
                <div className="bg-green-50 h-10 w-10 flex items-center justify-center rounded-full text-green-700 font-bold text-sm border border-green-100">
                  {student.roll_number || '০'}
                </div>
                <div>
                  <h3 className="font-bold text-gray-800">{student.student_name}</h3>
                  <p className="text-xs text-gray-500">অভিভাবক: {student.guardian_phone}</p>
                </div>
              </div>
              <div className="flex gap-1">
                <button 
                  onClick={(e) => { e.stopPropagation(); makeCall(student); }} 
                  className="bg-green-100 text-green-700 p-3 rounded-full hover:bg-green-200"
                >
                  <Phone size={18} fill="currentColor" />
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-gray-300">
            <p className="text-gray-500">এই ক্লাসে কোনো ছাত্র নেই।</p>
          </div>
        )}
      </div>

      <button 
        onClick={() => { setEditId(null); setFormData({name:'', phone:'', roll:''}); setShowModal(true); }}
        className="fixed bottom-24 right-6 bg-green-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center active:scale-90 transition-transform z-40"
      >
        <Plus size={28} />
      </button>

      {showDetails && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] sm:rounded-3xl p-8 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-start mb-6">
              <div className="bg-green-100 p-4 rounded-3xl text-green-700 mb-4 flex items-center gap-3">
                <User size={30} />
                <span className="text-xl font-bold">রোল: {showDetails.roll_number}</span>
              </div>
              <button onClick={() => setShowDetails(null)} className="p-2 bg-gray-100 rounded-full"><X size={20}/></button>
            </div>

            <div className="space-y-6">
              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">ছাত্রের নাম</h4>
                <p className="text-2xl font-bold text-gray-800">{showDetails.student_name}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">শ্রেণি</h4>
                <p className="text-lg font-medium text-gray-700">{className}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">অভিভাবকের ফোন</h4>
                <p className="text-xl font-mono font-bold text-green-700">{showDetails.guardian_phone}</p>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-4">
                <button 
                  onClick={() => makeCall(showDetails)}
                  className="flex items-center justify-center gap-2 bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-200 active:scale-95 transition-transform"
                >
                  <Phone size={20} fill="currentColor" />
                  কল করুন
                </button>
                <button 
                  onClick={() => startEdit(showDetails)}
                  className="flex items-center justify-center gap-2 bg-gray-100 text-gray-700 py-4 rounded-2xl font-bold active:scale-95 transition-transform"
                >
                  <Edit2 size={20} />
                  এডিট
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-[80] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-t-2xl sm:rounded-3xl p-6 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold">{editId ? 'তথ্য সংশোধন' : 'নতুন ছাত্র যোগ করুন'}</h3>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-full"><X /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-5">
              <div className="grid grid-cols-3 gap-4">
                <div className="col-span-1">
                  <label className="block text-sm font-bold text-gray-600 mb-2">রোল</label>
                  <input 
                    type="number" 
                    placeholder="১"
                    className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                    value={formData.roll}
                    onChange={e => setFormData({...formData, roll: e.target.value})}
                  />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-bold text-gray-600 mb-2">ছাত্রের নাম (বাংলায়)</label>
                  <input 
                    required
                    type="text" 
                    placeholder="উদাঃ আব্দুল্লাহ"
                    className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">অভিভাবকের মোবাইল নম্বর</label>
                <input 
                  required
                  type="tel" 
                  placeholder="01XXXXXXXXX"
                  className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                  value={formData.phone}
                  onChange={e => setFormData({...formData, phone: e.target.value})}
                />
              </div>
              <button type="submit" className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-100 active:scale-95 transition-all">
                {editId ? 'আপডেট করুন' : 'সংরক্ষণ করুন'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Students;

-- ১. মাদরাসা (প্রোফাইল) টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.madrasahs (
    id UUID REFERENCES auth.users ON DELETE CASCADE PRIMARY KEY,
    name TEXT NOT NULL DEFAULT 'নতুন মাদ্রাসা',
    phone TEXT,
    avatar_url TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ২. ক্লাস টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.classes (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    class_name TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৩. ছাত্র টেবিল তৈরি (রোল নম্বর সহ)
CREATE TABLE IF NOT EXISTS public.students (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    roll_number INTEGER DEFAULT 0,
    class_id UUID REFERENCES public.classes(id) ON DELETE CASCADE NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৪. সাম্প্রতিক কল টেবিল তৈরি
CREATE TABLE IF NOT EXISTS public.recent_calls (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    student_id UUID REFERENCES public.students(id) ON DELETE SET NULL,
    student_name TEXT NOT NULL,
    guardian_phone TEXT NOT NULL,
    madrasah_id UUID REFERENCES public.madrasahs(id) ON DELETE CASCADE NOT NULL,
    called_at TIMESTAMPTZ DEFAULT NOW()
);

-- ৫. আরএলএস (RLS) সক্রিয় করা
ALTER TABLE public.madrasahs ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.classes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.students ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.recent_calls ENABLE ROW LEVEL SECURITY;

-- ৬. পুরোনো পলিসি ক্লিনআপ এবং নতুন পলিসি তৈরি (এরর এড়াতে)
DO $$ BEGIN
    -- Madrasahs Policies
    DROP POLICY IF EXISTS "m_select" ON public.madrasahs;
    DROP POLICY IF EXISTS "m_update" ON public.madrasahs;
    DROP POLICY IF EXISTS "m_insert" ON public.madrasahs;

    -- Classes Policies
    DROP POLICY IF EXISTS "c_select" ON public.classes;
    DROP POLICY IF EXISTS "c_insert" ON public.classes;
    DROP POLICY IF EXISTS "c_update" ON public.classes;
    DROP POLICY IF EXISTS "c_delete" ON public.classes;

    -- Students Policies
    DROP POLICY IF EXISTS "s_select" ON public.students;
    DROP POLICY IF EXISTS "s_insert" ON public.students;
    DROP POLICY IF EXISTS "s_update" ON public.students;
    DROP POLICY IF EXISTS "s_delete" ON public.students;

    -- Recent Calls Policies
    DROP POLICY IF EXISTS "r_select" ON public.recent_calls;
    DROP POLICY IF EXISTS "r_insert" ON public.recent_calls;
EXCEPTION WHEN undefined_object THEN
    -- Ignore if policy doesn't exist
END $$;

-- নতুন পলিসি এসাইন করা
CREATE POLICY "m_select" ON public.madrasahs FOR SELECT USING (auth.uid() = id);
CREATE POLICY "m_update" ON public.madrasahs FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "m_insert" ON public.madrasahs FOR INSERT WITH CHECK (auth.uid() = id);

CREATE POLICY "c_select" ON public.classes FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "c_insert" ON public.classes FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "c_update" ON public.classes FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "c_delete" ON public.classes FOR DELETE USING (madrasah_id = auth.uid());

CREATE POLICY "s_select" ON public.students FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "s_insert" ON public.students FOR INSERT WITH CHECK (madrasah_id = auth.uid());
CREATE POLICY "s_update" ON public.students FOR UPDATE USING (madrasah_id = auth.uid());
CREATE POLICY "s_delete" ON public.students FOR DELETE USING (madrasah_id = auth.uid());

CREATE POLICY "r_select" ON public.recent_calls FOR SELECT USING (madrasah_id = auth.uid());
CREATE POLICY "r_insert" ON public.recent_calls FOR INSERT WITH CHECK (madrasah_id = auth.uid());

-- ১০. নতুন ইউজার হ্যান্ডলার ফাংশন এবং ট্রিগার (অটোমেটিক প্রোফাইল তৈরির জন্য)
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO public.madrasahs (id, name)
    VALUES (new.id, 'নতুন মাদ্রাসা')
    ON CONFLICT (id) DO NOTHING;
    RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
    AFTER INSERT ON auth.users
    FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

