import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './lib/supabase';
import Layout from './components/Layout';
import Home from './pages/Home';
import Classes from './pages/Classes';
import Students from './pages/Students';
import Account from './pages/Account';
import Login from './pages/Login';
import { AuthState, Madrasah } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    loading: true,
    madrasah: null,
  });

  const fetchMadrasahProfile = async (userId: string): Promise<Madrasah | null> => {
    try {
      const { data, error } = await supabase
        .from('madrasahs')
        .select('*')
        .eq('id', userId)
        .single();

      if (error || !data) {
        const { data: newData } = await supabase
          .from('madrasahs')
          .upsert({ id: userId, name: 'নতুন মাদরাসা' })
          .select('*')
          .single();
        return newData;
      }
      return data;
    } catch (err) {
      console.error("Profile fetch error:", err);
      return null;
    }
  };

  const refreshProfile = async () => {
    if (auth.user) {
      const madrasah = await fetchMadrasahProfile(auth.user.id);
      setAuth(prev => ({ ...prev, madrasah }));
    }
  };

  useEffect(() => {
    const checkUser = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const madrasah = await fetchMadrasahProfile(session.user.id);
          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err) {
        setAuth(prev => ({ ...prev, loading: false }));
      }
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
        const madrasah = await fetchMadrasahProfile(session.user.id);
        setAuth({ user: session.user, madrasah, loading: false });
      } else {
        setAuth({ user: null, madrasah: null, loading: false });
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (auth.loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-green-50 text-green-600 font-bold">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          <p>লোড হচ্ছে...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {auth.user ? (
          <Route element={<Layout madrasahName={auth.madrasah?.name || 'মাদরাসা'} />}>
            <Route path="/" element={<Home />} />
            <Route path="/classes" element={<Classes />} />
            <Route path="/classes/:classId" element={<Students />} />
            <Route path="/account" element={<Account madrasah={auth.madrasah} onUpdate={refreshProfile} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        ) : (
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Loader2, CheckCircle, Camera } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
  onUpdate?: () => void;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah, onUpdate }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialMadrasah) {
      setName(initialMadrasah.name);
      setPhone(initialMadrasah.phone || '');
      setAvatar(initialMadrasah.avatar_url || '');
    }
  }, [initialMadrasah]);

  useEffect(() => {
    const loadUser = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) setEmail(user.email || '');
    };
    loadUser();
  }, []);

  const handleUpdate = async () => {
    if (!name.trim()) return alert('মাদরাসার নাম দিন।');
    setSaving(true);
    setSuccess(false);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const { error } = await supabase.from('madrasahs').upsert({ 
        id: user.id, 
        name: name.trim(), 
        phone: phone.trim(),
        avatar_url: avatar 
      });

      if (error) throw error;

      setSuccess(true);
      if (onUpdate) onUpdate();
      setTimeout(() => setSuccess(false), 2000);
    } catch (err: any) {
      console.error("Update error:", err);
      alert('ত্রুটি: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // লিমিট চেক (৩ এমবির বেশি হলে রিজেক্ট করা)
      if (file.size > 3 * 1024 * 1024) {
        alert('ছবিটি ৩ মেগাবাইটের চেয়ে ছোট হতে হবে।');
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => setAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-6 max-w-lg mx-auto pb-10">
      <h2 className="text-2xl font-bold text-gray-800">অ্যাকাউন্ট প্রোফাইল</h2>
      <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 space-y-6">
        <div className="flex flex-col items-center">
          <div className="relative">
            <div className="w-32 h-32 bg-green-50 rounded-full flex items-center justify-center overflow-hidden border-4 border-white shadow-lg">
              {avatar ? <img src={avatar} className="w-full h-full object-cover" /> : <Building size={56} className="text-green-600 opacity-40" />}
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-1 right-1 bg-green-600 text-white p-2.5 rounded-full shadow-lg border-2 border-white">
              <Camera size={18} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImage} />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mt-4">{name || 'মাদরাসার নাম'}</h3>
          <p className="text-gray-400 text-sm">{email}</p>
        </div>

        <div className="space-y-4 pt-4 border-t border-gray-50">
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">মাদরাসার নাম (বাংলায়)</label>
            <input type="text" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={name} onChange={e => setName(e.target.value)} />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 mb-2">যোগাযোগ নম্বর</label>
            <input type="tel" className="w-full p-4 border border-gray-100 rounded-2xl bg-gray-50 focus:bg-white outline-none focus:ring-2 focus:ring-green-500" value={phone} onChange={e => setPhone(e.target.value)} placeholder="01XXXXXXXXX" />
          </div>

          <button onClick={handleUpdate} disabled={saving} className="w-full py-4 bg-green-600 text-white rounded-2xl font-bold flex items-center justify-center gap-2 shadow-lg disabled:opacity-70">
            {saving ? <Loader2 className="animate-spin" size={20} /> : success ? <CheckCircle size={20} /> : <Save size={20} />}
            {saving ? 'সংরক্ষণ হচ্ছে...' : success ? 'সফল!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>
      <button onClick={() => supabase.auth.signOut()} className="w-full bg-red-50 text-red-600 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 border border-red-100 active:scale-95 transition-all">
        <LogOut size={20} /> লগআউট
      </button>
    </div>
  );
};

export default Account;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { Phone, Plus, X, User, Edit2, ArrowLeft, Loader2, AlertCircle } from 'lucide-react';
import { Student } from '../types';

const Students: React.FC = () => {
  const { classId } = useParams();
  const navigate = useNavigate();
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showDetails, setShowDetails] = useState<Student | null>(null);
  const [className, setClassName] = useState('');

  const [editId, setEditId] = useState<string | null>(null);
  const [formData, setFormData] = useState({ name: '', phone: '', roll: '' });
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    fetchClassAndStudents();
  }, [classId]);

  const fetchClassAndStudents = async () => {
    if (!classId) return;

    try {
      const [classRes, studentRes] = await Promise.all([
        supabase.from('classes').select('class_name').eq('id', classId).single(),
        supabase.from('students')
          .select('*')
          .eq('class_id', classId)
          .order('roll_number', { ascending: true })
      ]);

      if (classRes.data) setClassName(classRes.data.class_name);
      if (studentRes.data) setStudents(studentRes.data);
    } catch (err) {
      console.error("Data fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.phone) return;

    setSubmitting(true);
    try {
      const { data: userData } = await supabase.auth.getUser();
      if (!userData.user || !classId) throw new Error("লগইন সেশন পাওয়া যায়নি।");

      const payload = {
        student_name: formData.name.trim(),
        guardian_phone: formData.phone.trim(),
        roll_number: parseInt(formData.roll) || 0,
        class_id: classId,
        madrasah_id: userData.user.id
      };

      let error;
      if (editId) {
        const res = await supabase.from('students').update(payload).eq('id', editId);
        error = res.error;
      } else {
        const res = await supabase.from('students').insert(payload);
        error = res.error;
      }

      if (error) {
        console.error("Supabase error:", error);
        throw new Error(error.message);
      }

      setShowModal(false);
      setEditId(null);
      setFormData({ name: '', phone: '', roll: '' });
      fetchClassAndStudents();
    } catch (err: any) {
      alert('ছাত্র যোগ/আপডেট করতে সমস্যা হয়েছে: ' + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const startEdit = (student: Student) => {
    setEditId(student.id);
    setFormData({ 
      name: student.student_name, 
      phone: student.guardian_phone, 
      roll: student.roll_number?.toString() || '' 
    });
    setShowDetails(null);
    setShowModal(true);
  };

  const makeCall = async (student: Student) => {
    try {
      await supabase.from('recent_calls').insert({
        student_id: student.id,
        student_name: student.student_name,
        guardian_phone: student.guardian_phone,
        madrasah_id: student.madrasah_id
      });
    } catch (e) {}
    window.location.href = `tel:${student.guardian_phone}`;
  };

  if (loading) return <div className="flex justify-center p-12"><Loader2 className="animate-spin text-green-600" /></div>;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/classes')} className="text-gray-500 hover:bg-gray-100 p-2 rounded-full transition-colors"><ArrowLeft /></button>
        <h2 className="text-2xl font-bold">{className}</h2>
      </div>

      <div className="space-y-3">
        {students.length > 0 ? (
          students.map((student) => (
            <div 
              key={student.id} 
              onClick={() => setShowDetails(student)}
              className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between active:bg-gray-50 transition-colors cursor-pointer"
            >
              <div className="flex items-center gap-3">
                <div className="bg-green-50 h-10 w-10 flex items-center justify-center rounded-full text-green-700 font-bold text-sm border border-green-100">
                  {student.roll_number || '০'}
                </div>
                <div>
                  <h3 className="font-bold text-gray-800">{student.student_name}</h3>
                  <p className="text-xs text-gray-500">অভিভাবক: {student.guardian_phone}</p>
                </div>
              </div>
              <div className="flex gap-1">
                <button 
                  onClick={(e) => { e.stopPropagation(); makeCall(student); }} 
                  className="bg-green-100 text-green-700 p-3 rounded-full hover:bg-green-200"
                >
                  <Phone size={18} fill="currentColor" />
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-gray-300">
            <p className="text-gray-500">এই ক্লাসে কোনো ছাত্র নেই।</p>
          </div>
        )}
      </div>

      <button 
        onClick={() => { setEditId(null); setFormData({name:'', phone:'', roll:''}); setShowModal(true); }}
        className="fixed bottom-24 right-6 bg-green-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center active:scale-90 transition-transform z-40"
      >
        <Plus size={28} />
      </button>

      {showDetails && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-md rounded-t-[2.5rem] sm:rounded-3xl p-8 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-start mb-6">
              <div className="bg-green-100 p-4 rounded-3xl text-green-700 mb-4 flex items-center gap-3">
                <User size={30} />
                <span className="text-xl font-bold">রোল: {showDetails.roll_number}</span>
              </div>
              <button onClick={() => setShowDetails(null)} className="p-2 bg-gray-100 rounded-full"><X size={20}/></button>
            </div>

            <div className="space-y-6">
              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">ছাত্রের নাম</h4>
                <p className="text-2xl font-bold text-gray-800">{showDetails.student_name}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">শ্রেণি</h4>
                <p className="text-lg font-medium text-gray-700">{className}</p>
              </div>

              <div>
                <h4 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-1">অভিভাবকের ফোন</h4>
                <p className="text-xl font-mono font-bold text-green-700">{showDetails.guardian_phone}</p>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-4">
                <button 
                  onClick={() => makeCall(showDetails)}
                  className="flex items-center justify-center gap-2 bg-green-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-green-200 active:scale-95 transition-transform"
                >
                  <Phone size={20} fill="currentColor" />
                  কল করুন
                </button>
                <button 
                  onClick={() => startEdit(showDetails)}
                  className="flex items-center justify-center gap-2 bg-gray-100 text-gray-700 py-4 rounded-2xl font-bold active:scale-95 transition-transform"
                >
                  <Edit2 size={20} />
                  এডিট
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/50 z-[80] flex items-end sm:items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-t-2xl sm:rounded-3xl p-6 animate-in slide-in-from-bottom duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold">{editId ? 'তথ্য সংশোধন' : 'নতুন ছাত্র যোগ করুন'}</h3>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-full"><X /></button>
            </div>
            <form onSubmit={handleSave} className="space-y-5">
              <div className="grid grid-cols-3 gap-4">
                <div className="col-span-1">
                  <label className="block text-sm font-bold text-gray-600 mb-2">রোল</label>
                  <input 
                    type="number" 
                    placeholder="১"
                    className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                    value={formData.roll}
                    onChange={e => setFormData({...formData, roll: e.target.value})}
                  />
                </div>
                <div className="col-span-2">
                  <label className="block text-sm font-bold text-gray-600 mb-2">ছাত্রের নাম (বাংলায়)</label>
                  <input 
                    required
                    type="text" 
                    placeholder="উদাঃ আব্দুল্লাহ"
                    className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-600 mb-2">অভিভাবকের মোবাইল নম্বর</label>
                <input 
                  required
                  type="tel" 
                  placeholder="01XXXXXXXXX"
                  className="w-full p-4 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-green-500 outline-none"
