import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { Search, Phone, Clock, User, Hash, Loader2, XCircle } from 'lucide-react';
import { RecentCall } from '../types';

const Home: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState<any[]>([]);
  const [recentCalls, setRecentCalls] = useState<RecentCall[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchRecentCalls();
  }, []);

  const fetchRecentCalls = async () => {
    const { data } = await supabase
      .from('recent_calls')
      .select('*')
      .order('called_at', { ascending: false })
      .limit(10);
    if (data) setRecentCalls(data);
  };

  const handleSearch = async (val: string) => {
    setSearchTerm(val);
    if (val.trim().length < 1) {
      setSearchResults([]);
      return;
    }

    setLoading(true);

    try {
      // ছাত্রের নাম অথবা রোল নম্বর দিয়ে সার্চ করা হচ্ছে
      const isNumeric = !isNaN(Number(val.trim()));

      let query = supabase
        .from('students')
        .select(`
          *,
          classes (
            class_name
          )
        `);

      if (isNumeric) {
        query = query.eq('roll_number', Number(val.trim()));
      } else {
        query = query.ilike('student_name', `%${val.trim()}%`);
      }

      const { data, error } = await query.limit(15);

      if (error) throw error;
      setSearchResults(data || []);
    } catch (err) {
      console.error("Search error:", err);
    } finally {
      setLoading(false);
    }
  };

  const makeCall = async (student: any) => {
    const phone = student.guardian_phone || student.phone;
    if (!phone) return;

    const { data: { user } } = await supabase.auth.getUser();

    // রিসেন্ট কল লিস্টে সেভ করা
    await supabase.from('recent_calls').insert({
      student_id: student.id || null,
      student_name: student.student_name || student.name,
      guardian_phone: phone,
      madrasah_id: user?.id,
      called_at: new Date().toISOString()
    });

    window.location.href = `tel:${phone}`;
    setTimeout(fetchRecentCalls, 1000);
  };

  return (
    <div className="space-y-6">
      {/* Search Section */}
      <section className="relative z-10">
        <div className="relative">
          <input
            type="text"
            placeholder="ছাত্রের নাম বা রোল লিখে খুঁজুন..."
            className="w-full p-5 pl-14 rounded-[2rem] border-none shadow-xl shadow-green-100/50 focus:ring-2 focus:ring-green-500 outline-none transition-all text-lg font-medium"
            value={searchTerm}
            onChange={(e) => handleSearch(e.target.value)}
          />
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-green-600" size={24} />
          {searchTerm && (
            <button 
              onClick={() => { setSearchTerm(''); setSearchResults([]); }}
              className="absolute right-5 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-500"
            >
              <XCircle size={20} />
            </button>
          )}
        </div>

        {/* Search Results Dropdown/List */}
        {searchTerm.trim().length > 0 && (
          <div className="mt-4 bg-white rounded-[2.5rem] shadow-2xl border border-green-50 overflow-hidden animate-in fade-in slide-in-from-top-4 duration-300">
            <div className="px-6 py-4 bg-green-50 border-b border-green-100 flex justify-between items-center">
              <span className="text-sm font-bold text-green-800 flex items-center gap-2">
                <Search size={14} /> অনুসন্ধানের ফলাফল
              </span>
              {loading && <Loader2 size={16} className="animate-spin text-green-600" />}
            </div>

            <div className="max-h-[60vh] overflow-y-auto">
              {loading ? (
                <div className="p-10 text-center flex flex-col items-center gap-2">
                  <Loader2 className="animate-spin text-green-600" size={32} />
                  <p className="text-gray-400 font-bold">খোঁজা হচ্ছে...</p>
                </div>
              ) : searchResults.length > 0 ? (
                searchResults.map((student) => (
                  <div 
                    key={student.id} 
                    className="p-5 border-b border-gray-50 flex items-center justify-between active:bg-green-50 transition-colors cursor-pointer"
                    onClick={() => makeCall(student)}
                  >
                    <div className="flex items-center gap-4">
                      <div className="h-12 w-12 bg-green-100 rounded-2xl flex items-center justify-center text-green-700 font-black text-sm border border-green-200">
                        {student.roll_number || '০'}
                      </div>
                      <div>
                        <h3 className="font-bold text-gray-900 text-lg">{student.student_name}</h3>
                        <p className="text-xs font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-md inline-block">
                          {student.classes?.class_name || 'শ্রেণিহীন'}
                        </p>
                      </div>
                    </div>
                    <div className="bg-green-600 text-white p-4 rounded-2xl shadow-lg shadow-green-100 active:scale-90 transition-transform">
                      <Phone size={20} fill="currentColor" />
                    </div>
                  </div>
                ))
              ) : (
                <div className="p-12 text-center text-gray-400">
                  <User size={40} className="mx-auto mb-2 opacity-20" />
                  <p className="font-bold">দুঃখিত, কোনো ছাত্র পাওয়া যায়নি!</p>
                  <p className="text-xs">সঠিক বানান বা রোল নম্বর দিয়ে পুনরায় চেষ্টা করুন।</p>
                </div>
              )}
            </div>
          </div>
        )}
      </section>

      {/* Recent Calls Section */}
      <section className={searchTerm ? 'opacity-30 pointer-events-none transition-opacity' : 'transition-opacity'}>
        <div className="flex items-center justify-between mb-5 px-2">
          <h2 className="text-xl font-black text-gray-800 flex items-center gap-2">
            <Clock size={22} className="text-green-600" />
            সাম্প্রতিক কলসমূহ
          </h2>
          <span className="text-[10px] bg-gray-100 text-gray-500 font-black px-2 py-1 rounded-full uppercase tracking-widest">সর্বশেষ ১০টি</span>
        </div>

        <div className="space-y-4">
          {recentCalls.length > 0 ? (
            recentCalls.map((call) => (
              <div 
                key={call.id} 
                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm flex items-center justify-between active:scale-[0.97] active:shadow-inner transition-all cursor-pointer group"
                onClick={() => makeCall({ student_name: call.student_name, guardian_phone: call.guardian_phone })}
              >
                <div className="flex items-center gap-4">
                  <div className="bg-gray-50 p-4 rounded-2xl text-gray-400 group-hover:bg-green-50 group-hover:text-green-600 transition-colors">
                    <User size={24} />
                  </div>
                  <div>
                    <h3 className="font-bold text-gray-800 text-lg">{call.student_name}</h3>
                    <div className="flex items-center gap-2 text-gray-400">
                      <Phone size={12} />
                      <p className="text-sm font-mono font-bold">{call.guardian_phone}</p>
                    </div>
                  </div>
                </div>
                <div className="text-right flex flex-col items-end gap-2">
                  <span className="text-[10px] text-gray-400 font-black bg-gray-50 px-2 py-1 rounded-lg">
                    {new Date(call.called_at).toLocaleTimeString('bn-BD', { hour: '2-digit', minute: '2-digit' })}
                  </span>
                  <div className="bg-green-50 p-3 rounded-full text-green-600 group-hover:bg-green-600 group-hover:text-white transition-all shadow-sm">
                    <Phone size={18} fill="currentColor" />
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-white p-16 text-center rounded-[3rem] border border-dashed border-gray-200 text-gray-400 flex flex-col items-center">
              <Clock size={48} className="mb-3 opacity-10" />
              <p className="font-bold text-gray-400">এখনও কোনো কল করা হয়নি!</p>
              <p className="text-xs mt-1">ছাত্রদের খুঁজে কল করুন, এখানে হিস্ট্রি জমা হবে।</p>
            </div>
          )}
        </div>
      </section>
    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Building, Lock, Phone, Loader2, ArrowRight, AlertCircle, Sparkles } from 'lucide-react';

const Login: React.FC = () => {
  const [phone, setPhone] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (phone.length < 11) {
      setError('সঠিক মোবাইল নম্বর প্রদান করুন (কমপক্ষে ১১ ডিজিট)।');
      setLoading(false);
      return;
    }

    try {
      const { error: authError } = await supabase.auth.signInWithPassword({ 
        email: `${phone}@madrasah.app`, 
        password: code 
      });

      if (authError) {
        if (authError.message.includes('Invalid login credentials')) {
          setError('মোবাইল নম্বর অথবা মাদরাসা কোড সঠিক নয়।');
        } else {
          setError(authError.message);
        }
      }
    } catch (err: any) {
      setError('নেটওয়ার্ক সমস্যা! অনুগ্রহ করে আবার চেষ্টা করুন।');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-[#f0f9f6] relative overflow-hidden">
      {/* Background Decorative Elements */}
      <div className="absolute top-[-10%] right-[-10%] w-80 h-80 bg-green-200 rounded-full blur-[100px] opacity-40"></div>
