          <h1 className="text-4xl font-black text-slate-800 tracking-tight mb-2">মাদরাসা কন্টাক্ট</h1>
          <p className="text-slate-500 font-medium">আপনার মাদরাসার ডিজিটাল ডিরেক্টরি</p>
        </div>

        <div className="bg-white/80 backdrop-blur-xl rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.05)] border border-white p-8 animate-slide-up" style={{animationDelay: '0.1s'}}>
          <form onSubmit={handleAuth} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">মোবাইল নম্বর</label>
              <div className="relative group">
                <input 
                  type="tel" 
                  required
                  placeholder="017XXXXXXXX"
                  className="w-full p-4 pl-12 bg-slate-50/50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 focus:bg-white outline-none transition-all font-mono text-lg"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                />
                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-green-600 transition-colors" size={20} />
              </div>
            </div>

            <div className="space-y-2">
