import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { supabase } from './lib/supabase';
import Layout from './components/Layout';
import Home from './pages/Home';
import Classes from './pages/Classes';
import Students from './pages/Students';
import Account from './pages/Account';
import Login from './pages/Login';
import ImportData from './pages/ImportData';
import { AuthState, Madrasah } from './types';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    loading: true,
    madrasah: null,
  });

  const fetchMadrasahProfile = async (userId: string): Promise<Madrasah | null> => {
    try {
      const { data, error } = await supabase
        .from('madrasahs')
        .select('*')
        .eq('id', userId)
        .single();

      if (error || !data) {
        const { data: newData } = await supabase
          .from('madrasahs')
          .upsert({ id: userId, name: 'নতুন মাদরাসা' })
          .select('*')
          .single();
        return newData;
      }
      return data;
    } catch (err) {
      console.error("Profile fetch error:", err);
      return null;
    }
  };

  const refreshProfile = async () => {
    if (auth.user) {
      const madrasah = await fetchMadrasahProfile(auth.user.id);
      setAuth(prev => ({ ...prev, madrasah }));
    }
  };

  useEffect(() => {
    const checkUser = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        if (session?.user) {
          const madrasah = await fetchMadrasahProfile(session.user.id);
          setAuth({ user: session.user, madrasah, loading: false });
        } else {
          setAuth({ user: null, madrasah: null, loading: false });
        }
      } catch (err) {
        setAuth(prev => ({ ...prev, loading: false }));
      }
    };

    checkUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user) {
        const madrasah = await fetchMadrasahProfile(session.user.id);
        setAuth({ user: session.user, madrasah, loading: false });
      } else {
        setAuth({ user: null, madrasah: null, loading: false });
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  if (auth.loading) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-green-50 text-green-600 font-bold">
        <div className="flex flex-col items-center gap-4">
          <div className="h-12 w-12 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          <p>লোড হচ্ছে...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        {auth.user ? (
          <Route element={<Layout madrasah={auth.madrasah} />}>
            <Route path="/" element={<Home />} />
            <Route path="/classes" element={<Classes />} />
            <Route path="/classes/:classId" element={<Students />} />
            <Route path="/import" element={<ImportData />} />
            <Route path="/account" element={<Account madrasah={auth.madrasah} onUpdate={refreshProfile} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Route>
        ) : (
          <>
            <Route path="/login" element={<Login />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </>
        )}
      </Routes>
    </Router>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Loader2, CheckCircle, Camera, Mail, ShieldCheck } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
  onUpdate?: () => void;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah, onUpdate }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialMadrasah) {
      setName(initialMadrasah.name);
      setPhone(initialMadrasah.phone || '');
      setAvatar(initialMadrasah.avatar_url || '');
    }
    supabase.auth.getUser().then(({ data }) => setEmail(data.user?.email || ''));
  }, [initialMadrasah]);

  const handleUpdate = async () => {
    if (!name.trim()) return;
    setSaving(true);
    setSuccess(false);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      // madrasah_code is kept in the DB but not exposed in the UI
      await supabase.from('madrasahs').upsert({ 
        id: user?.id, 
        name, 
        phone, 
        avatar_url: avatar 
      });
      setSuccess(true);
      if (onUpdate) onUpdate();
      setTimeout(() => setSuccess(false), 2000);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = async () => {
    try {
      const { error } = await supabase.auth.signOut();
      if (error) throw error;
      // After signout, the App component state will update via onAuthStateChange
    } catch (err) {
      console.error("Logout error:", err);
      // Forced clean up
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-8 pb-10">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-black text-slate-800">অ্যাকাউন্ট</h2>
