import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { BookOpen, Plus, ChevronRight, Loader2, AlertCircle, Sparkles, LayoutGrid, FileUp } from 'lucide-react';
import { ClassRoom } from '../types';

const Classes: React.FC = () => {
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newClassName, setNewClassName] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    fetchClasses();
  }, []);

  const fetchClasses = async () => {
    try {
      setLoading(true);
      const { data, error: fetchError } = await supabase
        .from('classes')
        .select('*')
        .order('created_at', { ascending: false });

      if (fetchError) throw fetchError;
      setClasses(data || []);
    } catch (err: any) {
      console.error(err);
      setError("তথ্য লোড করতে সমস্যা হয়েছে।");
    } finally {
      setLoading(false);
    }
  };

  const addClass = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const name = newClassName.trim();
    if (!name) return;

    try {
      const { data: { user } } = await supabase.auth.getUser();
      const { error: insError } = await supabase.from('classes').insert({
        class_name: name,
        madrasah_id: user?.id
      });
      if (insError) throw insError;
      setNewClassName('');
      setIsAdding(false);
      fetchClasses();
    } catch (err: any) {
      setError("ক্লাস যোগ করা যায়নি।");
    }
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-[60vh] gap-4">
      <Loader2 className="animate-spin text-green-600" size={40} />
      <p className="text-slate-400 font-bold">ক্লাস লোড হচ্ছে...</p>
    </div>
  );

  return (
    <div className="space-y-8 pb-10">
      <div className="flex items-center justify-between px-2">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-green-100 rounded-xl">
             <LayoutGrid size={24} className="text-green-600" />
          </div>
          <h2 className="text-3xl font-black text-slate-800">শ্রেণি তালিকা</h2>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => navigate('/import')} 
            className="bg-emerald-50 text-emerald-600 p-4 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all border border-emerald-100"
            title="ডাটা ইমপোর্ট করুন"
          >
            <FileUp size={20} />
          </button>
          <button 
            onClick={() => setIsAdding(!isAdding)} 
            className="bg-green-600 text-white p-4 rounded-2xl flex items-center gap-2 font-black shadow-lg shadow-green-100 active:scale-90 transition-all"
          >
            <Plus size={20} /> নতুন ক্লাস
          </button>
        </div>
      </div>

      {isAdding && (
        <form onSubmit={addClass} className="bg-white p-8 rounded-[2.5rem] border border-green-100 shadow-[0_20px_40px_rgba(0,0,0,0.03)] space-y-5 animate-slide-up">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">শ্রেণির নাম লিখুন</label>
            <input 
              className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-green-500/10 focus:border-green-500 font-bold text-slate-700" 
              placeholder="যেমন: ১ম শ্রেণি বা তাইসীর" 
              value={newClassName}
              onChange={e => setNewClassName(e.target.value)}
              autoFocus
            />
          </div>
          <button type="submit" className="w-full bg-green-600 text-white py-5 rounded-3xl font-black shadow-lg shadow-green-100 active:scale-[0.98] transition-all flex items-center justify-center gap-2">
            <Sparkles size={20} />
            যুক্ত করুন
          </button>
        </form>
      )}

      {error && (
        <div className="bg-red-50 text-red-600 p-5 rounded-3xl border border-red-100 flex items-start gap-3">
          <AlertCircle className="shrink-0" />
          <p className="text-sm font-bold">{error}</p>
        </div>
      )}

      <div className="grid gap-5">
        {classes.length > 0 ? (
          classes.map(cls => (
            <div 
              key={cls.id} 
              onClick={() => navigate(`/classes/${cls.id}`)} 
              className="bg-white p-6 rounded-[2.5rem] shadow-[0_4px_20px_rgba(0,0,0,0.02)] border border-white flex items-center justify-between cursor-pointer active:scale-[0.98] transition-all group hover:border-green-100"
            >
              <div className="flex items-center gap-5">
                <div className="bg-slate-50 w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-slate-300 group-hover:bg-green-50 group-hover:text-green-600 transition-colors">
                  <BookOpen size={30} />
                </div>
                <div>
                  <h3 className="font-black text-slate-800 text-xl group-hover:text-green-700 transition-colors">{cls.class_name}</h3>
                  <div className="flex items-center gap-1.5 mt-1">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ভিউ ডিটেইলস</span>
                  </div>
                </div>
              </div>
              <div className="bg-slate-50 p-3 rounded-2xl text-slate-300 group-hover:bg-green-600 group-hover:text-white transition-all">
                <ChevronRight size={24} />
              </div>
            </div>
          ))
        ) : !isAdding && (
          <div className="text-center py-24 bg-white rounded-[3rem] border border-dashed border-slate-200 flex flex-col items-center">
            <BookOpen size={64} className="mb-4 opacity-5" />
            <p className="font-bold text-slate-300 text-lg">কোনো ক্লাস নেই!</p>
            <p className="text-xs text-slate-400 mt-2 italic">শুরু করতে "নতুন ক্লাস" বাটনে ক্লিক করুন</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Classes;

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../lib/supabase';
import { LogOut, Building, Save, Loader2, CheckCircle, Camera, Mail, ShieldCheck, Key } from 'lucide-react';
import { Madrasah } from '../types';

interface AccountProps {
  madrasah: Madrasah | null;
  onUpdate?: () => void;
}

const Account: React.FC<AccountProps> = ({ madrasah: initialMadrasah, onUpdate }) => {
  const [name, setName] = useState(initialMadrasah?.name || '');
  const [phone, setPhone] = useState(initialMadrasah?.phone || '');
  const [code, setCode] = useState(initialMadrasah?.madrasah_code || '');
  const [avatar, setAvatar] = useState(initialMadrasah?.avatar_url || '');
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState(false);
  const [email, setEmail] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialMadrasah) {
      setName(initialMadrasah.name);
      setPhone(initialMadrasah.phone || '');
      setCode(initialMadrasah.madrasah_code || '');
      setAvatar(initialMadrasah.avatar_url || '');
    }
    supabase.auth.getUser().then(({ data }) => setEmail(data.user?.email || ''));
  }, [initialMadrasah]);

  const handleUpdate = async () => {
    if (!name.trim()) return;
    setSaving(true);
    setSuccess(false);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      const { error } = await supabase.from('madrasahs').upsert({ 
        id: user?.id, 
        name, 
        phone, 
        madrasah_code: code,
        avatar_url: avatar 
      });
      if (error) throw error;
      setSuccess(true);
      if (onUpdate) onUpdate();
      setTimeout(() => setSuccess(false), 2000);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  const handleLogout = async () => {
    try {
      const { error } = await supabase.auth.signOut();
      if (error) throw error;
    } catch (err) {
      console.error("Logout error:", err);
      localStorage.clear();
      window.location.reload();
    }
  };

  const handleImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatar(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-8 pb-10">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-black text-slate-800">অ্যাকাউন্ট</h2>
        <div className="px-3 py-1 bg-green-50 text-green-600 text-[10px] font-bold rounded-full border border-green-100 uppercase tracking-widest">
          অনলাইন সেশন
        </div>
      </div>

      <div className="bg-white rounded-[3rem] shadow-[0_20px_50px_rgba(0,0,0,0.03)] border border-white p-8 space-y-8">
        <div className="flex flex-col items-center">
          <div className="relative">
            <div className="w-36 h-36 bg-slate-50 rounded-[2.5rem] flex items-center justify-center overflow-hidden border-4 border-white shadow-2xl">
              {avatar ? <img src={avatar} className="w-full h-full object-cover" /> : <Building size={64} className="text-slate-200" />}
            </div>
            <button onClick={() => fileInputRef.current?.click()} className="absolute -bottom-2 -right-2 bg-green-600 text-white p-3.5 rounded-2xl shadow-xl shadow-green-200 border-2 border-white active:scale-90 transition-transform">
              <Camera size={20} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImage} />
          </div>
          <h3 className="text-2xl font-black text-slate-800 mt-6">{name}</h3>
          <div className="flex items-center gap-2 text-slate-400 mt-1 font-bold">
             <ShieldCheck size={14} className="text-green-500" />
             <span className="text-xs uppercase tracking-widest">ভেরিফাইড মাদরাসা এডমিন</span>
          </div>
        </div>

        <div className="space-y-5 pt-4 border-t border-slate-50">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">মাদরাসার নাম</label>
            <input type="text" className="w-full p-5 bg-slate-50/50 border border-slate-100 rounded-3xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 outline-none transition-all font-bold text-slate-700" value={name} onChange={e => setName(e.target.value)} />
          </div>

          {/* মাদরাসা কোড কলাম যোগ করা হয়েছে */}
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">মাদরাসা কোড (লগইন পাসওয়ার্ড)</label>
            <div className="relative">
              <input 
                type="text" 
                className="w-full p-5 pl-14 bg-slate-50/50 border border-slate-100 rounded-3xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 outline-none transition-all font-bold text-slate-700" 
                value={code} 
                onChange={e => setCode(e.target.value)} 
                placeholder="মাদরাসা কোড দিন"
              />
              <Key className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">যোগাযোগের নম্বর</label>
            <input type="tel" className="w-full p-5 bg-slate-50/50 border border-slate-100 rounded-3xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 outline-none transition-all font-bold text-slate-700" value={phone} onChange={e => setPhone(e.target.value)} />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">অফিসিয়াল ইমেইল</label>
            <div className="p-5 bg-slate-50/50 border border-slate-100 rounded-3xl text-slate-400 flex items-center gap-3">
              <Mail size={18} />
              <span className="font-bold text-sm">{email}</span>
            </div>
          </div>

          <button 
            onClick={handleUpdate} 
            disabled={saving} 
            className="w-full py-5 bg-green-600 text-white rounded-[2rem] font-black flex items-center justify-center gap-3 shadow-xl shadow-green-100 disabled:opacity-70 mt-4 active:scale-[0.98] transition-all"
          >
            {saving ? <Loader2 className="animate-spin" size={24} /> : success ? <CheckCircle size={24} /> : <Save size={24} />}
            {saving ? 'আপডেট হচ্ছে...' : success ? 'তথ্য সংরক্ষিত!' : 'তথ্য আপডেট করুন'}
          </button>
        </div>
      </div>

      <button onClick={handleLogout} className="w-full bg-red-50 text-red-600 py-5 rounded-[2rem] font-black flex items-center justify-center gap-3 border border-red-100 active:bg-red-100 active:scale-[0.98] transition-all mb-10">
        <LogOut size={24} /> লগআউট করুন
      </button>
    </div>
  );
};

export default Account;

