import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Building, Lock, Phone, Loader2, ArrowRight, AlertCircle, Sparkles, UserPlus } from 'lucide-react';

const Login: React.FC = () => {
  const [isRegister, setIsRegister] = useState(false);
  const [phone, setPhone] = useState('');
  const [code, setCode] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const cleanPhone = phone.trim();
    if (cleanPhone.length < 11) {
      setError('সঠিক মোবাইল নম্বর প্রদান করুন (কমপক্ষে ১১ ডিজিট)।');
      setLoading(false);
      return;
    }

    if (code.length < 6) {
      setError('মাদরাসা কোড বা পাসওয়ার্ড কমপক্ষে ৬ ডিজিটের হতে হবে।');
      setLoading(false);
      return;
    }

    const email = `${cleanPhone}@madrasah.app`;

    try {
      if (isRegister) {
        // Registration Logic
        const { data, error: signUpError } = await supabase.auth.signUp({
          email,
          password: code,
          options: {
            data: { display_name: name || 'নতুন মাদরাসা' }
          }
        });

        if (signUpError) throw signUpError;

        // Update the madrasah profile immediately after signup
        if (data.user) {
          await supabase.from('madrasahs').upsert({
            id: data.user.id,
            name: name || 'নতুন মাদরাসা',
            madrasah_code: code,
            phone: cleanPhone
          });
        }
        alert('অ্যাকাউন্ট তৈরি সফল হয়েছে! এখন লগইন করুন।');
        setIsRegister(false);
      } else {
        // Login Logic
        const { error: authError } = await supabase.auth.signInWithPassword({ 
          email, 
          password: code 
        });

        if (authError) {
          if (authError.message.includes('Invalid login credentials')) {
            setError('মোবাইল নম্বর অথবা মাদরাসা কোড সঠিক নয়।');
          } else {
            setError(authError.message);
          }
        }
      }
    } catch (err: any) {
      setError(err.message || 'নেটওয়ার্ক সমস্যা! আবার চেষ্টা করুন।');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 bg-[#f0f9f6] relative overflow-hidden">
      <div className="absolute top-[-10%] right-[-10%] w-80 h-80 bg-green-200 rounded-full blur-[100px] opacity-40"></div>
      <div className="absolute bottom-[-10%] left-[-10%] w-96 h-96 bg-emerald-200 rounded-full blur-[120px] opacity-40"></div>

      <div className="w-full max-w-md relative z-10">
        <div className="text-center mb-10 animate-slide-up">
          <div className="inline-flex p-4 bg-white rounded-[2rem] shadow-xl shadow-green-100 mb-6">
            <div className="w-16 h-16 bg-green-600 text-white rounded-[1.5rem] flex items-center justify-center shadow-lg shadow-green-200">
              <Building size={32} />
            </div>
          </div>
          <h1 className="text-4xl font-black text-slate-800 tracking-tight mb-2">মাদরাসা কন্টাক্ট</h1>
          <p className="text-slate-500 font-medium">আপনার মাদরাসার ডিজিটাল ডিরেক্টরি</p>
        </div>

        <div className="bg-white/80 backdrop-blur-xl rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.05)] border border-white p-8 animate-slide-up" style={{animationDelay: '0.1s'}}>
          <div className="flex bg-slate-100 p-1.5 rounded-2xl mb-8">
            <button 
              onClick={() => { setIsRegister(false); setError(''); }}
              className={`flex-1 py-3 rounded-xl font-black text-sm transition-all ${!isRegister ? 'bg-white text-green-600 shadow-sm' : 'text-slate-400'}`}
            >
              লগইন
            </button>
            <button 
              onClick={() => { setIsRegister(true); setError(''); }}
              className={`flex-1 py-3 rounded-xl font-black text-sm transition-all ${isRegister ? 'bg-white text-green-600 shadow-sm' : 'text-slate-400'}`}
            >
              রেজিস্ট্রেশন
            </button>
          </div>

          <form onSubmit={handleAuth} className="space-y-5">
            {isRegister && (
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">মাদরাসার নাম</label>
                <input 
                  type="text" 
                  required
                  placeholder="মাদরাসার নাম লিখুন"
                  className="w-full p-4 bg-slate-50/50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 focus:bg-white outline-none transition-all font-bold"
                  value={name}
                  onChange={e => setName(e.target.value)}
                />
              </div>
            )}

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">মোবাইল নম্বর</label>
              <div className="relative group">
                <input 
                  type="tel" 
                  required
                  placeholder="01XXXXXXXXX"
                  className="w-full p-4 pl-12 bg-slate-50/50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 focus:bg-white outline-none transition-all font-mono text-lg"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                />
                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-green-600 transition-colors" size={20} />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">
                {isRegister ? 'মাদরাসা কোড (পাসওয়ার্ড)' : 'মাদরাসা কোড'}
              </label>
              <div className="relative group">
                <input 
                  type="password" 
                  required
                  placeholder="কমপক্ষে ৬ ডিজিট"
                  className="w-full p-4 pl-12 bg-slate-50/50 border border-slate-100 rounded-2xl focus:ring-4 focus:ring-green-500/10 focus:border-green-500 focus:bg-white outline-none transition-all text-lg"
                  value={code}
                  onChange={e => setCode(e.target.value)}
                />
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-green-600 transition-colors" size={20} />
              </div>
            </div>

            {error && (
              <div className="bg-red-50 text-red-600 p-4 rounded-2xl border border-red-100 flex gap-3 items-center animate-shake">
                <AlertCircle size={20} className="shrink-0" />
                <span className="text-sm font-bold leading-tight">{error}</span>
              </div>
            )}

            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-green-700 active:scale-[0.98] transition-all shadow-xl shadow-green-200 mt-2 disabled:opacity-70"
            >
              {loading ? <Loader2 className="animate-spin" size={24} /> : (
                <>
                  {isRegister ? 'অ্যাকাউন্ট খুলুন' : 'লগইন করুন'}
                  {isRegister ? <UserPlus size={20} /> : <ArrowRight size={20} />}
                </>
              )}
            </button>
          </form>
        </div>

        <div className="mt-12 text-center animate-slide-up" style={{animationDelay: '0.2s'}}>
          <div className="inline-flex items-center gap-2 px-4 py-2 bg-white rounded-full shadow-sm border border-slate-100 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
            <Sparkles size={12} className="text-amber-400" /> সুরক্ষিত ও সহজ ব্যবস্থাপনা
          </div>
          <p className="mt-6 text-slate-400 text-xs px-10 leading-relaxed">
            রেজিস্ট্রেশন করার সময় দেওয়া মোবাইল নম্বর এবং কোড ভবিষ্যতে লগইন করার জন্য সংরক্ষণ করুন।
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useRef, useEffect } from 'react';
