    if (initialMadrasah?.id) {
      navigator.clipboard.writeText(initialMadrasah.id);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const handleLogout = async () => {
    try {
      const { error } = await supabase.auth.signOut();
      if (error) throw error;
